const TOKEN_KEY = 'rekrutai_token'
const REFRESH_KEY = 'rekrutai_refresh'

export function getToken(): string | null {
  return localStorage.getItem(TOKEN_KEY)
}

export function getRefreshToken(): string | null {
  return localStorage.getItem(REFRESH_KEY)
}

export function setTokens(accessToken: string, refreshToken: string) {
  localStorage.setItem(TOKEN_KEY, accessToken)
  localStorage.setItem(REFRESH_KEY, refreshToken)
}

export function clearTokens() {
  localStorage.removeItem(TOKEN_KEY)
  localStorage.removeItem(REFRESH_KEY)
}

let isRefreshing = false
let refreshPromise: Promise<string | null> | null = null

async function refreshAccessToken(): Promise<string | null> {
  if (isRefreshing && refreshPromise) return refreshPromise

  isRefreshing = true
  refreshPromise = (async () => {
    try {
      const refreshToken = getRefreshToken()
      if (!refreshToken) return null

      const res = await fetch('/api/auth/refresh', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ refreshToken }),
      })

      if (!res.ok) return null

      const data = await res.json()
      if (data.accessToken && data.refreshToken) {
        setTokens(data.accessToken, data.refreshToken)
        return data.accessToken
      }
      return null
    } catch {
      return null
    } finally {
      isRefreshing = false
      refreshPromise = null
    }
  })()

  return refreshPromise
}

interface ApiCallOptions extends Omit<RequestInit, 'body'> {
  body?: unknown
  isFormData?: boolean
}

export async function apiCall<T = unknown>(
  url: string,
  options: ApiCallOptions = {}
): Promise<T> {
  const { body, isFormData, headers: customHeaders, ...rest } = options
  const token = getToken()

  const headers: Record<string, string> = {
    ...(customHeaders as Record<string, string>),
  }

  if (token) {
    headers['Authorization'] = `Bearer ${token}`
  }

  if (!isFormData && body) {
    headers['Content-Type'] = 'application/json'
  }

  const fetchOptions: RequestInit = {
    ...rest,
    headers,
    body: isFormData ? (body as BodyInit) : body ? JSON.stringify(body) : undefined,
  }

  let res = await fetch(`/api${url}`, fetchOptions)

  // If 401, try to refresh token
  if (res.status === 401) {
    const newToken = await refreshAccessToken()
    if (newToken) {
      headers['Authorization'] = `Bearer ${newToken}`
      res = await fetch(`/api${url}`, { ...fetchOptions, headers })
    } else {
      clearTokens()
      window.location.href = '/login'
      throw new Error('Session expired')
    }
  }

  if (!res.ok) {
    const errorData = await res.json().catch(() => ({ error: 'Request failed' }))
    throw new Error(errorData.error || `Request failed: ${res.status}`)
  }

  return res.json()
}

export type UserRole = 'candidate' | 'recruiter' | 'hiring_manager' | 'employer' | 'admin'

export interface User {
  id: number
  email: string
  name: string
  role: UserRole
  company_name?: string
  avatar_url?: string
}

export function isRecruiterRole(role: UserRole): boolean {
  return ['employer', 'recruiter', 'hiring_manager', 'admin'].includes(role)
}

export function getDashboardPath(role: UserRole): string {
  return isRecruiterRole(role) ? '/recruiter' : '/candidate'
}

import { createContext, useContext, useEffect, useState, useCallback, type ReactNode } from 'react'
import {
  apiCall,
  setTokens,
  clearTokens,
  getToken,
  getDashboardPath,
  isRecruiterRole,
  type User,
  type UserRole,
} from '@/lib/api'

interface AuthContextType {
  user: User | null
  loading: boolean
  isAuthenticated: boolean
  isRecruiter: boolean
  login: (email: string, password: string) => Promise<void>
  register: (data: RegisterData) => Promise<void>
  logout: () => void
}

interface RegisterData {
  email: string
  password: string
  name: string
  role: UserRole
  company_name?: string
}

const AuthContext = createContext<AuthContextType | undefined>(undefined)

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null)
  const [loading, setLoading] = useState(true)

  const checkAuth = useCallback(async () => {
    const token = getToken()
    if (!token) {
      setLoading(false)
      return
    }

    try {
      const data = await apiCall<{ user: User }>('/auth/me')
      setUser(data.user)
    } catch {
      clearTokens()
      setUser(null)
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => {
    checkAuth()
  }, [checkAuth])

  const login = async (email: string, password: string) => {
    const data = await apiCall<{
      success: boolean
      user: User
      accessToken: string
      refreshToken: string
      token: string
    }>('/auth/login', {
      method: 'POST',
      body: { email, password },
    })

    setTokens(data.accessToken || data.token, data.refreshToken)
    setUser(data.user)
  }

  const register = async (registerData: RegisterData) => {
    const data = await apiCall<{
      success: boolean
      user: User
      accessToken: string
      refreshToken: string
      token: string
    }>('/auth/register', {
      method: 'POST',
      body: registerData,
    })

    setTokens(data.accessToken || data.token, data.refreshToken)
    setUser(data.user)
  }

  const logout = () => {
    clearTokens()
    setUser(null)
    window.location.href = '/login'
  }

  return (
    <AuthContext.Provider
      value={{
        user,
        loading,
        isAuthenticated: !!user,
        isRecruiter: user ? isRecruiterRole(user.role) : false,
        login,
        register,
        logout,
      }}
    >
      {children}
    </AuthContext.Provider>
  )
}

export function useAuth() {
  const context = useContext(AuthContext)
  if (!context) {
    throw new Error('useAuth must be used within AuthProvider')
  }
  return context
}

export { getDashboardPath }

import { useEffect, useState, useRef } from 'react'
import { apiCall } from '@/lib/api'
import { useAuth } from '@/contexts/auth-context'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { Badge } from '@/components/ui/badge'
import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/components/ui/tabs'
import { Dialog, DialogHeader, DialogTitle } from '@/components/ui/dialog'
import {
  User, Briefcase, GraduationCap, Wrench, FileText,
  Plus, Pencil, Trash2, Save, Upload, MapPin, Phone, Link2,
  Github, Linkedin, Globe, CheckCircle, AlertCircle, X,
  Calendar, Building2, Award, Star, Sparkles, Loader2,
} from 'lucide-react'

// ============= Types =============

interface Profile {
  user_id?: number
  name?: string
  email?: string
  avatar_url?: string
  headline?: string
  bio?: string
  location?: string
  phone?: string
  linkedin_url?: string
  github_url?: string
  portfolio_url?: string
  resume_url?: string
  availability?: string
  salary_min?: number
  salary_max?: number
  preferred_job_types?: string[]
  preferred_locations?: string[]
  remote_preference?: string
  years_experience?: number
}

interface Experience {
  id: number
  company_name: string
  title: string
  location?: string
  start_date?: string
  end_date?: string
  is_current?: boolean
  description?: string
  achievements?: string[]
  skills_used?: string[]
}

interface Education {
  id: number
  institution: string
  degree: string
  field_of_study?: string
  start_date?: string
  end_date?: string
  is_current?: boolean
  gpa?: string
  achievements?: string[]
}

interface Skill {
  id: number
  skill_name: string
  category: string
  level: number
  years_experience?: number
  is_verified?: boolean
}

// ============= Main Component =============

export function CandidateProfilePage() {
  const { user } = useAuth()
  const [tab, setTab] = useState('personal')
  const [profile, setProfile] = useState<Profile>({})
  const [experience, setExperience] = useState<Experience[]>([])
  const [education, setEducation] = useState<Education[]>([])
  const [skills, setSkills] = useState<Skill[]>([])
  const [loading, setLoading] = useState(true)
  const [saving, setSaving] = useState(false)
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null)
  const [aiOptimizing, setAiOptimizing] = useState(false)
  const [aiTips, setAiTips] = useState<string[] | null>(null)

  useEffect(() => {
    loadProfile()
  }, [])

  useEffect(() => {
    if (message) {
      const t = setTimeout(() => setMessage(null), 3000)
      return () => clearTimeout(t)
    }
  }, [message])

  async function loadProfile() {
    try {
      const data = await apiCall<{
        success: boolean
        profile: Profile
        experience: Experience[]
        education: Education[]
        skills: Skill[]
      }>('/candidate/profile')
      setProfile({ ...data.profile, name: data.profile.name || user?.name, email: data.profile.email || user?.email })
      setExperience(data.experience || [])
      setEducation(data.education || [])
      setSkills(data.skills || [])
    } catch {
      // silent
    } finally {
      setLoading(false)
    }
  }

  function showMessage(type: 'success' | 'error', text: string) {
    setMessage({ type, text })
  }

  // Compute profile completeness
  async function handleAiOptimize() {
    setAiOptimizing(true)
    setAiTips(null)
    try {
      const data = await apiCall<{ success: boolean; suggestions: { summary: string; improvements: string[]; missing_sections: string[]; keyword_suggestions: string[] } }>('/candidate/ai/resume-optimizer', { method: 'POST' })
      if (data.suggestions) {
        const tips: string[] = []
        if (data.suggestions.summary) tips.push(data.suggestions.summary)
        if (data.suggestions.improvements?.length) tips.push(...data.suggestions.improvements)
        if (data.suggestions.missing_sections?.length) tips.push(`Missing sections: ${data.suggestions.missing_sections.join(', ')}`)
        if (data.suggestions.keyword_suggestions?.length) tips.push(`Add keywords: ${data.suggestions.keyword_suggestions.join(', ')}`)
        setAiTips(tips.length > 0 ? tips : ['Your profile looks great! Keep it updated.'])
        showMessage('success', 'AI analysis complete')
      }
    } catch {
      showMessage('error', 'AI optimization failed — try again')
    } finally {
      setAiOptimizing(false)
    }
  }

  const completenessFields = [
    profile.name,
    profile.headline,
    profile.bio,
    profile.location,
    profile.linkedin_url || profile.github_url,
    profile.resume_url,
    skills.length > 0,
    experience.length > 0,
    education.length > 0,
    profile.phone,
  ]
  const completeness = Math.round((completenessFields.filter(Boolean).length / completenessFields.length) * 100)

  if (loading) {
    return (
      <div className="flex items-center justify-center py-16">
        <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
      </div>
    )
  }

  return (
    <div className="space-y-6">
      {/* Toast message */}
      {message && (
        <div className={`fixed top-4 right-4 z-50 flex items-center gap-2 rounded-lg px-4 py-3 text-sm font-medium shadow-lg transition-all ${
          message.type === 'success' ? 'bg-emerald-600 text-white' : 'bg-destructive text-white'
        }`}>
          {message.type === 'success' ? <CheckCircle className="h-4 w-4" /> : <AlertCircle className="h-4 w-4" />}
          {message.text}
        </div>
      )}

      {/* Header */}
      <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h1 className="font-heading text-2xl font-bold">My Profile</h1>
          <p className="text-muted-foreground">Manage your professional profile for employers</p>
        </div>
        <div className="flex items-center gap-3">
          <Button
            variant="outline"
            size="sm"
            onClick={handleAiOptimize}
            disabled={aiOptimizing}
            className="gap-1.5 border-primary/30 text-primary hover:bg-primary hover:text-white transition-colors"
          >
            {aiOptimizing ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <Sparkles className="h-3.5 w-3.5" />}
            {aiOptimizing ? 'Analyzing...' : 'AI Profile Tips'}
          </Button>
          <ProfileCompleteness value={completeness} />
        </div>
      </div>

      {/* AI Optimization Tips */}
      {aiTips && aiTips.length > 0 && (
        <Card className="border-blue-200 bg-blue-50/50 dark:border-blue-800 dark:bg-blue-950/20">
          <CardContent className="p-4">
            <div className="flex items-start gap-3">
              <Sparkles className="h-5 w-5 text-blue-600 mt-0.5 shrink-0" />
              <div className="flex-1 space-y-2">
                <div className="flex items-center justify-between">
                  <h4 className="font-semibold text-blue-900 dark:text-blue-100 text-sm">AI Profile Optimization Tips</h4>
                  <Button variant="ghost" size="sm" onClick={() => setAiTips(null)} className="h-6 w-6 p-0"><X className="h-3 w-3" /></Button>
                </div>
                <ul className="space-y-1.5">
                  {aiTips.map((tip, i) => (
                    <li key={i} className="text-sm text-blue-800 dark:text-blue-200 flex items-start gap-2">
                      <CheckCircle className="h-3.5 w-3.5 mt-0.5 shrink-0 text-blue-500" />
                      {tip}
                    </li>
                  ))}
                </ul>
              </div>
            </div>
          </CardContent>
