              <div>
                <Label>Start Date</Label>
                <Input type="date" value={editing.start_date?.split('T')[0] || ''} onChange={e => setEditing({ ...editing, start_date: e.target.value })} />
              </div>
              <div>
                <Label>End Date</Label>
                <Input type="date" value={editing.end_date?.split('T')[0] || ''} onChange={e => setEditing({ ...editing, end_date: e.target.value })} />
              </div>
            </div>
            <div className="flex justify-end gap-2 pt-2">
              <Button variant="outline" onClick={() => setEditing(null)}>Cancel</Button>
              <Button onClick={handleSave} disabled={!editing.institution || !editing.degree} className="gap-1">
                <Save className="h-4 w-4" /> {isNew ? 'Add' : 'Save'}
              </Button>
            </div>
          </div>
        </Dialog>
      )}
    </div>
  )
}

// ============= Skills Tab =============

function SkillsTab({ skills, setSkills, showMessage }: {
  skills: Skill[]
  setSkills: React.Dispatch<React.SetStateAction<Skill[]>>
  showMessage: (type: 'success' | 'error', text: string) => void
}) {
  const [newSkill, setNewSkill] = useState('')
  const [newCategory, setNewCategory] = useState('technical')
  const [newLevel, setNewLevel] = useState(3)
  const [adding, setAdding] = useState(false)

  async function addSkill() {
    if (!newSkill.trim()) return
    setAdding(true)
    try {
      const data = await apiCall<{ success: boolean; skill: Skill }>('/candidate/skills', {
        method: 'POST',
        body: { skill_name: newSkill.trim(), category: newCategory, level: newLevel },
      })
      setSkills(prev => [...prev, data.skill])
      setNewSkill('')
      setNewLevel(3)
      showMessage('success', 'Skill added')
    } catch {
      showMessage('error', 'Failed to add skill')
    } finally {
      setAdding(false)
    }
  }

  async function updateLevel(skill: Skill, level: number) {
    try {
      await apiCall(`/candidate/skills/${skill.id}`, {
        method: 'PUT',
        body: { level },
      })
      setSkills(prev => prev.map(s => s.id === skill.id ? { ...s, level } : s))
    } catch {
      showMessage('error', 'Failed to update skill')
    }
  }

  async function removeSkill(id: number) {
    try {
      await apiCall(`/candidate/skills/${id}`, { method: 'DELETE' })
      setSkills(prev => prev.filter(s => s.id !== id))
      showMessage('success', 'Skill removed')
    } catch {
      showMessage('error', 'Failed to delete skill')
    }
  }

  const levelLabels: Record<number, string> = { 1: 'Beginner', 2: 'Elementary', 3: 'Intermediate', 4: 'Advanced', 5: 'Expert' }

  // Group skills by category
  const grouped = skills.reduce((acc, s) => {
    const cat = s.category || 'other'
    if (!acc[cat]) acc[cat] = []
    acc[cat].push(s)
    return acc
  }, {} as Record<string, Skill[]>)

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h3 className="font-semibold flex items-center gap-2"><Wrench className="h-4 w-4" /> Skills ({skills.length})</h3>
      </div>

      {/* Add skill form */}
      <Card>
        <CardContent className="p-4">
          <p className="text-sm font-medium mb-3">Add a Skill</p>
          <div className="flex flex-col gap-3 sm:flex-row sm:items-end">
            <div className="flex-1">
              <Label>Skill Name</Label>
              <Input
                value={newSkill}
                onChange={e => setNewSkill(e.target.value)}
                placeholder="e.g. React, Python, Project Management"
                onKeyDown={e => e.key === 'Enter' && addSkill()}
              />
            </div>
            <div className="w-36">
              <Label>Category</Label>
              <select
                value={newCategory}
                onChange={e => setNewCategory(e.target.value)}
                className="flex h-9 w-full rounded-md border border-input bg-transparent px-3 py-1 text-sm shadow-sm"
              >
                <option value="technical">Technical</option>
                <option value="soft">Soft Skills</option>
                <option value="language">Language</option>
                <option value="tool">Tools</option>
                <option value="other">Other</option>
              </select>
            </div>
            <div className="w-36">
              <Label>Level ({levelLabels[newLevel]})</Label>
              <Input type="range" min={1} max={5} value={newLevel} onChange={e => setNewLevel(parseInt(e.target.value))} />
            </div>
            <Button onClick={addSkill} disabled={!newSkill.trim() || adding} className="gap-1">
              <Plus className="h-4 w-4" /> Add
            </Button>
          </div>
        </CardContent>
      </Card>

      {skills.length === 0 ? (
        <Card>
          <CardContent className="py-12 text-center">
            <Wrench className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground">No skills added yet. Add your skills above.</p>
          </CardContent>
        </Card>
      ) : (
        Object.entries(grouped).map(([category, categorySkills]) => (
          <div key={category}>
            <h4 className="text-sm font-medium text-muted-foreground mb-2 capitalize">{category} Skills</h4>
            <div className="grid gap-2 sm:grid-cols-2">
              {categorySkills.map(skill => (
                <Card key={skill.id}>
                  <CardContent className="p-3 flex items-center gap-3">
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2">
                        <span className="font-medium text-sm truncate">{skill.skill_name}</span>
                        {skill.is_verified && (
                          <Badge variant="success" className="gap-0.5 text-[10px]">
                            <Award className="h-2.5 w-2.5" /> Verified
                          </Badge>
                        )}
                      </div>
                      <div className="flex items-center gap-1 mt-1">
                        {[1, 2, 3, 4, 5].map(level => (
                          <button
                            key={level}
                            onClick={() => updateLevel(skill, level)}
                            className="focus:outline-none"
                          >
                            <Star
                              className={`h-3.5 w-3.5 transition-colors ${
                                level <= skill.level ? 'fill-amber-400 text-amber-400' : 'text-muted-foreground/30'
                              }`}
                            />
                          </button>
                        ))}
                        <span className="text-[10px] text-muted-foreground ml-1">{levelLabels[skill.level]}</span>
                      </div>
                    </div>
                    <Button variant="ghost" size="sm" onClick={() => removeSkill(skill.id)} className="shrink-0 text-muted-foreground hover:text-destructive">
                      <X className="h-3.5 w-3.5" />
                    </Button>
                  </CardContent>
                </Card>
              ))}
            </div>
          </div>
        ))
      )}
    </div>
  )
}

// ============= Resume Tab =============

interface ApplySummary {
  profile?: boolean
  experience?: number
  education?: number
  skills?: number
}

interface ParsedData {
  contact?: { name?: string; email?: string; phone?: string; location?: string; linkedin?: string; github?: string; portfolio?: string }
  headline?: string
  bio?: string
  experience?: Array<{ company: string; title: string; location?: string; start_date?: string; end_date?: string; description?: string }>
  education?: Array<{ institution: string; degree?: string; field?: string; start_date?: string; end_date?: string }>
  skills?: Array<{ name: string; category?: string; level?: number }>
  years_experience?: number
  _applySummary?: ApplySummary
}

function ResumeTab({ profile, setProfile, showMessage, onResumeApplied }: {
  profile: Profile
  setProfile: React.Dispatch<React.SetStateAction<Profile>>
  showMessage: (type: 'success' | 'error', text: string) => void
  onResumeApplied: () => Promise<void>
}) {
  const fileRef = useRef<HTMLInputElement>(null)
  const [uploading, setUploading] = useState(false)
  const [lastParsed, setLastParsed] = useState<ParsedData | null>(null)
  const [parseStep, setParseStep] = useState<string>('')

  async function handleUpload(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0]
    if (!file) return
    setUploading(true)
    setLastParsed(null)
    setParseStep('Uploading resume...')
    try {
      setParseStep('Analyzing with AI...')
      const formData = new FormData()
      formData.append('resume', file)
      const data = await apiCall<{ success: boolean; resume_url: string; parsed_data?: ParsedData }>('/candidate/resume/upload', {
        method: 'POST',
        body: formData,
        isFormData: true,
      })
      setProfile(p => ({ ...p, resume_url: data.resume_url }))

      if (data.parsed_data) {
        setLastParsed(data.parsed_data)
        setParseStep('Refreshing profile...')
        // Reload the full profile to reflect auto-applied data
        await onResumeApplied()

        const summary = data.parsed_data._applySummary
        if (summary) {
          const parts: string[] = []
          if (summary.profile) parts.push('profile info')
          if (summary.experience && summary.experience > 0) parts.push(`${summary.experience} job${summary.experience > 1 ? 's' : ''}`)
          if (summary.education && summary.education > 0) parts.push(`${summary.education} education`)
          if (summary.skills && summary.skills > 0) parts.push(`${summary.skills} skill${summary.skills > 1 ? 's' : ''}`)

          if (parts.length > 0) {
            showMessage('success', `AI imported: ${parts.join(', ')}`)
          } else {
            showMessage('success', 'Resume parsed — profile already up to date')
          }
        } else {
          showMessage('success', 'Resume uploaded & parsed!')
        }
      } else {
        showMessage('success', 'Resume uploaded')
      }
      setParseStep('')
    } catch {
      showMessage('error', 'Failed to upload resume')
      setParseStep('')
    } finally {
      setUploading(false)
      // Reset file input so same file can be re-uploaded
      if (fileRef.current) fileRef.current.value = ''
    }
  }

  return (
    <div className="space-y-4">
      <h3 className="font-semibold flex items-center gap-2"><FileText className="h-4 w-4" /> Resume</h3>

      <Card>
        <CardContent className="p-6">
          {profile.resume_url ? (
            <div className="space-y-4">
              <div className="flex items-center gap-3 rounded-lg border p-4 bg-muted/50">
                <FileText className="h-8 w-8 text-primary shrink-0" />
                <div className="flex-1 min-w-0">
                  <p className="font-medium">Current Resume</p>
                  <p className="text-sm text-muted-foreground truncate">{profile.resume_url}</p>
                </div>
                <a href={profile.resume_url} target="_blank" rel="noopener noreferrer">
                  <Button variant="outline" size="sm">View</Button>
                </a>
              </div>
              <div className="flex gap-2">
                <Button onClick={() => fileRef.current?.click()} variant="outline" className="gap-1" disabled={uploading}>
                  {uploading ? (
                    <div className="h-4 w-4 animate-spin rounded-full border-2 border-primary border-t-transparent" />
                  ) : (
                    <Upload className="h-4 w-4" />
                  )}
                  {uploading ? 'Processing...' : 'Replace Resume'}
                </Button>
              </div>
              {uploading && parseStep && (
                <div className="flex items-center gap-2 text-sm text-primary animate-pulse">
                  <div className="h-3 w-3 animate-spin rounded-full border-2 border-primary border-t-transparent" />
                  {parseStep}
                </div>
              )}
            </div>
          ) : (
            <div className="text-center py-8">
              <div className="mx-auto mb-4 flex h-16 w-16 items-center justify-center rounded-full bg-muted">
                <Upload className="h-8 w-8 text-muted-foreground" />
              </div>
              <h4 className="font-semibold mb-1">Upload Your Resume</h4>
              <p className="text-sm text-muted-foreground mb-4">
                Upload a PDF or DOCX (max 10MB). AI will automatically parse your resume and fill in your profile.
              </p>
              <Button onClick={() => fileRef.current?.click()} disabled={uploading} className="gap-2">
                {uploading ? (
                  <div className="h-4 w-4 animate-spin rounded-full border-2 border-white border-t-transparent" />
                ) : (
                  <Upload className="h-4 w-4" />
                )}
                {uploading ? 'Analyzing...' : 'Choose File'}
              </Button>
              {uploading && parseStep && (
                <p className="text-sm text-primary mt-3 animate-pulse">{parseStep}</p>
              )}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Show parsed data summary after successful import */}
      {lastParsed && !uploading && (
        <Card className="border-emerald-200 bg-emerald-50/50 dark:border-emerald-800 dark:bg-emerald-950/20">
          <CardContent className="p-5">
            <div className="flex items-start gap-3">
              <CheckCircle className="h-5 w-5 text-emerald-600 mt-0.5 shrink-0" />
              <div className="flex-1 space-y-3">
                <div>
                  <h4 className="font-semibold text-emerald-900 dark:text-emerald-100">AI Resume Import Complete</h4>
                  <p className="text-sm text-emerald-700 dark:text-emerald-300">
                    Your profile has been auto-filled from your resume. Review each tab to confirm the data is correct.
                  </p>
                </div>

                {/* Summary grid */}
                <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
                  {lastParsed.contact && (
                    <div className="rounded-md bg-white/60 dark:bg-white/5 px-3 py-2 text-center">
                      <User className="h-4 w-4 mx-auto mb-1 text-emerald-600" />
                      <p className="text-xs font-medium">Profile Info</p>
                      <p className="text-[10px] text-muted-foreground">{lastParsed.contact.name || 'Updated'}</p>
                    </div>
                  )}
                  {lastParsed.experience && lastParsed.experience.length > 0 && (
                    <div className="rounded-md bg-white/60 dark:bg-white/5 px-3 py-2 text-center">
                      <Briefcase className="h-4 w-4 mx-auto mb-1 text-emerald-600" />
                      <p className="text-xs font-medium">{lastParsed.experience.length} Job{lastParsed.experience.length > 1 ? 's' : ''}</p>
                      <p className="text-[10px] text-muted-foreground truncate">{lastParsed.experience[0]?.company}</p>
                    </div>
                  )}
                  {lastParsed.education && lastParsed.education.length > 0 && (
                    <div className="rounded-md bg-white/60 dark:bg-white/5 px-3 py-2 text-center">
                      <GraduationCap className="h-4 w-4 mx-auto mb-1 text-emerald-600" />
                      <p className="text-xs font-medium">{lastParsed.education.length} Education</p>
                      <p className="text-[10px] text-muted-foreground truncate">{lastParsed.education[0]?.institution}</p>
                    </div>
                  )}
                  {lastParsed.skills && lastParsed.skills.length > 0 && (
                    <div className="rounded-md bg-white/60 dark:bg-white/5 px-3 py-2 text-center">
                      <Wrench className="h-4 w-4 mx-auto mb-1 text-emerald-600" />
                      <p className="text-xs font-medium">{lastParsed.skills.length} Skills</p>
                      <p className="text-[10px] text-muted-foreground truncate">{lastParsed.skills.slice(0, 3).map(s => s.name).join(', ')}</p>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </CardContent>
        </Card>
      )}

      <input ref={fileRef} type="file" accept=".pdf,.doc,.docx" className="hidden" onChange={handleUpload} />
    </div>
  )
}

import { useEffect, useState } from 'react'
import { Link } from 'react-router-dom'
import { apiCall } from '@/lib/api'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Badge } from '@/components/ui/badge'
import { Select } from '@/components/ui/select'
import {
  Briefcase, MapPin, DollarSign, Clock, Search, Building2, ArrowRight,
  Sparkles, Target, Zap, Star,
} from 'lucide-react'

interface Job {
  id: number
  title: string
  company: string
  poster_company?: string
  description: string
  requirements: string
  location: string
  salary_range: string
  job_type: string
  status: string
  created_at: string
  screening_questions?: string
  // Match fields (from recommended endpoint)
  weighted_score?: number
  match_level?: string
  skill_match_pct?: number
  matching_skills?: string[]
  missing_skills?: string[]
  success_prediction?: string
  similarity_score?: number
}

function matchColor(score: number): string {
  if (score >= 80) return 'text-green-600'
  if (score >= 60) return 'text-amber-600'
  return 'text-red-500'
}

function matchBg(score: number): string {
  if (score >= 80) return 'bg-green-100 text-green-700 border-green-200'
  if (score >= 60) return 'bg-amber-100 text-amber-700 border-amber-200'
  return 'bg-red-100 text-red-600 border-red-200'
}

function matchLevelLabel(level: string): string {
  if (level === 'excellent') return 'Excellent Match'
  if (level === 'good') return 'Good Match'
  if (level === 'fair') return 'Fair Match'
  return ''
}

export function CandidateJobsPage() {
  const [jobs, setJobs] = useState<Job[]>([])
  const [recommendedJobs, setRecommendedJobs] = useState<Job[]>([])
  const [loading, setLoading] = useState(true)
  const [search, setSearch] = useState('')
  const [typeFilter, setTypeFilter] = useState('')
  const [locationFilter, setLocationFilter] = useState('')
  const [showRecommended, setShowRecommended] = useState(true)

  useEffect(() => {
    loadJobs()
  }, [])

  async function loadJobs() {
    try {
      // Load both: all jobs + recommended (with match scores)
      const [allData, recData] = await Promise.allSettled([
        apiCall<{ jobs: Job[] }>('/jobs?status=active&limit=100'),
        apiCall<{ recommended_jobs: Job[] }>('/candidate/jobs/recommended'),
      ])

      const allJobs = allData.status === 'fulfilled' ? allData.value.jobs || [] : []
      const recJobs = recData.status === 'fulfilled' ? recData.value.recommended_jobs || [] : []

      // Merge match scores into all jobs
      const recMap = new Map<number, Job>()
      for (const rj of recJobs) {
        recMap.set(rj.job_id ?? rj.id, rj)
      }

      const enriched = allJobs.map(j => {
        const rec = recMap.get(j.id)
        if (rec) {
          return {
            ...j,
            weighted_score: rec.weighted_score,
            match_level: rec.match_level,
            skill_match_pct: rec.skill_match_pct,
            matching_skills: rec.matching_skills,
            missing_skills: rec.missing_skills,
            success_prediction: rec.success_prediction,
            similarity_score: rec.similarity_score,
          }
        }
        return j
      })

      setJobs(enriched)
      setRecommendedJobs(recJobs.slice(0, 5))
    } catch {
      // silent
    } finally {
      setLoading(false)
    }
  }

  const filtered = jobs.filter(j => {
    const matchSearch = !search ||
      j.title?.toLowerCase().includes(search.toLowerCase()) ||
      j.company?.toLowerCase().includes(search.toLowerCase()) ||
      j.description?.toLowerCase().includes(search.toLowerCase())
    const matchType = !typeFilter || j.job_type === typeFilter
    const matchLocation = !locationFilter || j.location?.toLowerCase().includes(locationFilter.toLowerCase())
    return matchSearch && matchType && matchLocation
  })

  const jobTypes = [...new Set(jobs.map(j => j.job_type).filter(Boolean))]

  function timeAgo(dateStr: string) {
    const diff = Date.now() - new Date(dateStr).getTime()
    const days = Math.floor(diff / 86400000)
    if (days === 0) return 'Today'
    if (days === 1) return '1 day ago'
    if (days < 30) return `${days} days ago`
    return `${Math.floor(days / 30)} months ago`
  }

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-heading text-2xl font-bold">Job Board</h1>
        <p className="text-muted-foreground">Find your next opportunity</p>
      </div>

      {/* Recommended jobs section */}
      {showRecommended && recommendedJobs.length > 0 && (
        <div>
          <div className="flex items-center gap-2 mb-3">
            <Sparkles className="h-4 w-4 text-primary" />
            <h2 className="font-semibold text-sm">Recommended for You</h2>
            <Badge variant="secondary" className="text-[10px]">{recommendedJobs.length} matches</Badge>
            <Button variant="ghost" size="sm" className="ml-auto text-xs" onClick={() => setShowRecommended(false)}>
              Hide
            </Button>
          </div>
          <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-3">
            {recommendedJobs.map(rj => {
              const jobId = (rj as any).job_id ?? rj.id
              const score = Math.round(rj.weighted_score || 0)
              return (
                <Link key={jobId} to={`/candidate/jobs/${jobId}`}>
                  <Card className="h-full transition-shadow hover:shadow-md cursor-pointer border-primary/20">
                    <CardContent className="p-4">
                      <div className="flex items-start justify-between gap-2 mb-2">
                        <div className="min-w-0">
                          <h3 className="font-semibold text-sm truncate">{rj.title}</h3>
                          <p className="text-xs text-muted-foreground">{rj.company}</p>
                        </div>
                        <div className={`text-center rounded-lg border px-2 py-0.5 shrink-0 ${matchBg(score)}`}>
                          <div className="text-sm font-bold">{score}%</div>
                        </div>
                      </div>
                      <div className="flex flex-wrap items-center gap-2 text-[10px] text-muted-foreground mb-2">
                        {rj.location && <span className="flex items-center gap-0.5"><MapPin className="h-2.5 w-2.5" />{rj.location}</span>}
                        {rj.job_type && <Badge variant="secondary" className="text-[9px] h-4">{rj.job_type}</Badge>}
                      </div>
                      {rj.match_level && (
                        <div className="flex items-center gap-1">
                          {rj.match_level === 'excellent' && <Zap className="h-3 w-3 text-green-500" />}
                          <span className={`text-[10px] font-medium ${matchColor(score)}`}>
                            {matchLevelLabel(rj.match_level)}
                          </span>
                          {rj.skill_match_pct != null && (
                            <span className="text-[10px] text-muted-foreground">
                              · {rj.skill_match_pct}% skills
                            </span>
                          )}
                        </div>
                      )}
                    </CardContent>
                  </Card>
                </Link>
              )
            })}
          </div>
        </div>
      )}

      {/* Filters */}
      <Card>
        <CardContent className="p-4">
          <div className="flex flex-col gap-3 sm:flex-row">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
              <Input
                placeholder="Search jobs by title, company, or keywords..."
                value={search}
                onChange={e => setSearch(e.target.value)}
                className="pl-9"
              />
            </div>
            <Select value={typeFilter} onChange={e => setTypeFilter(e.target.value)} className="sm:w-40">
              <option value="">All Types</option>
              {jobTypes.map(t => <option key={t} value={t}>{t}</option>)}
            </Select>
            <Input
              placeholder="Location..."
              value={locationFilter}
              onChange={e => setLocationFilter(e.target.value)}
              className="sm:w-40"
            />
          </div>
        </CardContent>
      </Card>

      {/* Results count */}
      <p className="text-sm text-muted-foreground">{filtered.length} jobs found</p>

      {/* Job list */}
      {loading ? (
        <div className="flex items-center justify-center py-16">
          <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
        </div>
      ) : filtered.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <Briefcase className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground">No jobs found matching your criteria</p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-3">
          {filtered.map(job => {
            const score = job.weighted_score ? Math.round(job.weighted_score) : null
            return (
              <Link key={job.id} to={`/candidate/jobs/${job.id}`}>
                <Card className="transition-shadow hover:shadow-md cursor-pointer">
                  <CardContent className="p-5">
                    <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
                      <div className="min-w-0 flex-1">
                        <div className="flex items-center gap-2 mb-1">
                          <h3 className="font-semibold text-base truncate">{job.title}</h3>
                          {job.match_level === 'excellent' && (
                            <Badge variant="outline" className="text-[10px] gap-0.5 text-green-600 border-green-200 bg-green-50 shrink-0">
                              <Zap className="h-2.5 w-2.5" /> Top Match
                            </Badge>
                          )}
                          {(() => {
                            try {
                              return job.screening_questions && JSON.parse(job.screening_questions).length > 0
                            } catch { return false }
                          })() && (
                            <Badge variant="outline" className="text-[10px] shrink-0">Screening</Badge>
                          )}
                        </div>
                        <div className="flex flex-wrap items-center gap-3 text-sm text-muted-foreground mb-2">
                          <span className="flex items-center gap-1">
                            <Building2 className="h-3.5 w-3.5" />
                            {job.company || job.poster_company || 'Company'}
                          </span>
                          {job.location && (
                            <span className="flex items-center gap-1">
                              <MapPin className="h-3.5 w-3.5" /> {job.location}
                            </span>
                          )}
                          {job.salary_range && (
                            <span className="flex items-center gap-1">
                              <DollarSign className="h-3.5 w-3.5" /> {job.salary_range}
                            </span>
                          )}
                        </div>
                        <p className="text-sm text-muted-foreground line-clamp-2">
                          {job.description?.substring(0, 200)}
                        </p>
                        {/* Skills match inline */}
                        {job.matching_skills && job.matching_skills.length > 0 && (
                          <div className="flex flex-wrap items-center gap-1 mt-2">
                            <Target className="h-3 w-3 text-green-500 shrink-0" />
                            {job.matching_skills.slice(0, 4).map(s => (
                              <span key={s} className="text-[10px] bg-green-50 text-green-700 rounded px-1.5 py-0.5 border border-green-100">{s}</span>
                            ))}
                            {job.matching_skills.length > 4 && (
                              <span className="text-[10px] text-green-600">+{job.matching_skills.length - 4} more</span>
                            )}
                          </div>
                        )}
                      </div>
                      <div className="flex items-center gap-3 shrink-0">
                        <div className="flex flex-col items-end gap-1">
                          {score != null && (
                            <div className={`text-center rounded-lg border px-2.5 py-1 ${matchBg(score)}`}>
                              <div className="text-lg font-bold leading-tight">{score}%</div>
                              <div className="text-[9px] uppercase font-medium">Match</div>
                            </div>
                          )}
                          {job.job_type && <Badge variant="secondary" className="text-[10px]">{job.job_type}</Badge>}
                          <span className="flex items-center gap-1 text-xs text-muted-foreground">
                            <Clock className="h-3 w-3" /> {timeAgo(job.created_at)}
                          </span>
                        </div>
                        <ArrowRight className="h-4 w-4 text-muted-foreground" />
                      </div>
                    </div>
                  </CardContent>
                </Card>
              </Link>
            )
          })}
        </div>
      )}
    </div>
  )
}

import { useEffect, useState } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { apiCall } from '@/lib/api'
import { useAuth } from '@/contexts/auth-context'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Textarea } from '@/components/ui/textarea'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Select } from '@/components/ui/select'
import {
  ArrowLeft, MapPin, DollarSign, Building2, Clock, Briefcase, Send,
  CheckCircle, AlertCircle, FileText, ListChecks, Sparkles, Loader2, Wand2, Zap,
} from 'lucide-react'

interface Job {
  id: number; title: string; company: string; poster_company?: string
  description: string; requirements: string; location: string
  salary_range: string; job_type: string
  screening_questions?: string | ScreeningQuestion[]
  created_at: string
}

interface ScreeningQuestion {
  id?: string; question: string; type?: 'text' | 'yes_no' | 'select'
  required?: boolean; options?: string[]; placeholder?: string; category?: string
}

interface AutoFillData {
  resume_url: string | null; cover_letter: string
  screening_answers: Record<string, { value: string; source: string }>
  profile: { name: string; email: string; phone: string; location: string }
}

export function CandidateJobDetailPage() {
  const { id } = useParams()
  const navigate = useNavigate()
  const { user } = useAuth()
  const [job, setJob] = useState<Job | null>(null)
  const [loading, setLoading] = useState(true)
  const [applying, setApplying] = useState(false)
  const [applied, setApplied] = useState(false)
  const [showApplyForm, setShowApplyForm] = useState(false)
  const [coverLetter, setCoverLetter] = useState('')
  const [screeningAnswers, setScreeningAnswers] = useState<Record<string, string>>({})
  const [errors, setErrors] = useState<Record<string, string>>({})
  const [autoFill, setAutoFill] = useState<AutoFillData | null>(null)
  const [autoFillSources, setAutoFillSources] = useState<Record<string, string>>({})
  const [generatingCL, setGeneratingCL] = useState(false)
  const [generatingSuggestions, setGeneratingSuggestions] = useState(false)

  useEffect(() => {
    loadJob()
    if (user) checkIfApplied()
  }, [id, user])

  async function loadJob() {
    try {
      const data = await apiCall<{ job: Job }>(`/jobs/${id}`)
      setJob(data.job)
    } catch {} finally { setLoading(false) }
  }

  async function checkIfApplied() {
    try {
      const data = await apiCall<{ success: boolean; applications: { job_id: number }[] }>('/candidate/applications')
      if (data.applications?.some(a => a.job_id === Number(id))) setApplied(true)
    } catch {}
  }

  // Auto-fill from stored profile data
  async function loadAutoFill() {
    if (!user || !id) return
    try {
      const data = await apiCall<{ success: boolean; auto_fill: AutoFillData }>(`/candidate/auto-fill/${id}`)
      if (data.auto_fill) {
        setAutoFill(data.auto_fill)
        // Pre-fill cover letter if available
        if (data.auto_fill.cover_letter && !coverLetter) {
          setCoverLetter(data.auto_fill.cover_letter)
        }
        // Pre-fill screening answers
        const newAnswers: Record<string, string> = { ...screeningAnswers }
        const sources: Record<string, string> = {}
        for (const [qId, info] of Object.entries(data.auto_fill.screening_answers || {})) {
          if (!newAnswers[qId] && info.value) {
            newAnswers[qId] = info.value
            sources[qId] = info.source
          }
        }
        setScreeningAnswers(newAnswers)
        setAutoFillSources(sources)
      }
    } catch {}
  }

  useEffect(() => {
    if (showApplyForm && user) loadAutoFill()
  }, [showApplyForm])

  const screeningQuestions: ScreeningQuestion[] = (() => {
    if (!job?.screening_questions) return []
    try {
      const raw = typeof job.screening_questions === 'string'
        ? JSON.parse(job.screening_questions) : job.screening_questions
      return Array.isArray(raw) ? raw : []
    } catch { return [] }
  })()

  function validateForm(): boolean {
    const newErrors: Record<string, string> = {}
    screeningQuestions.forEach((q, i) => {
      const key = q.id || `q${i}`
      if (q.required && !screeningAnswers[key]?.trim()) newErrors[key] = 'This question is required'
    })
    setErrors(newErrors)
    return Object.keys(newErrors).length === 0
  }

  async function handleApply() {
    if (!job) return
    if (!validateForm()) return
    setApplying(true)
    try {
      await apiCall(`/candidate/jobs/${job.id}/apply`, {
        method: 'POST',
        body: { cover_letter: coverLetter, screening_answers: screeningAnswers },
      })
      setApplied(true)
      setShowApplyForm(false)
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Failed to apply')
    } finally { setApplying(false) }
  }

  // AI: Generate cover letter
  async function generateCoverLetter() {
    if (!job) return
    setGeneratingCL(true)
    try {
      const data = await apiCall<{ success: boolean; cover_letter: string }>('/candidate/ai/cover-letter', {
        method: 'POST', body: { job_id: job.id },
      })
      if (data.cover_letter) setCoverLetter(data.cover_letter)
    } catch (err: unknown) {
      alert('AI generation failed. Try again.')
    } finally { setGeneratingCL(false) }
  }

  // AI: Get screening answer suggestions
  async function getSuggestions() {
    if (!job || screeningQuestions.length === 0) return
    setGeneratingSuggestions(true)
    try {
      const data = await apiCall<{ success: boolean; suggestions: Array<{ question_id: string; suggested_answer: string; source: string; confidence: string }> }>(
        '/candidate/ai/screening-suggestions',
        { method: 'POST', body: { job_id: job.id, questions: screeningQuestions } }
      )
      if (data.suggestions?.length) {
        const newAnswers = { ...screeningAnswers }
        const sources = { ...autoFillSources }
        for (const s of data.suggestions) {
          const key = s.question_id || screeningQuestions.find(q => q.id === s.question_id)?.id
          if (key && !newAnswers[key]) {
            newAnswers[key] = s.suggested_answer
            sources[key] = `ai_${s.confidence}`
          }
        }
        setScreeningAnswers(newAnswers)
        setAutoFillSources(sources)
      }
    } catch {} finally { setGeneratingSuggestions(false) }
  }

  function updateAnswer(key: string, value: string) {
    setScreeningAnswers(prev => ({ ...prev, [key]: value }))
    // Clear source badge when user manually edits
    setAutoFillSources(prev => { const n = { ...prev }; delete n[key]; return n })
    if (errors[key]) setErrors(prev => { const n = { ...prev }; delete n[key]; return n })
  }

  function sourceLabel(source: string) {
    if (source === 'previous_application') return 'From previous application'
    if (source === 'similar_question') return 'From similar question'
    if (source === 'profile') return 'From your profile'
    if (source.startsWith('ai_')) return '✨ AI suggestion'
    return null
  }

  function renderScreeningInput(q: ScreeningQuestion, index: number) {
    const key = q.id || `q${index}`
    const value = screeningAnswers[key] || ''
    const error = errors[key]
    const source = autoFillSources[key]
    const type = q.type || 'text'

    return (
      <div className="space-y-1">
        {source && (
          <Badge variant="outline" className="text-xs mb-1 gap-1">
            {source.startsWith('ai_') ? <Sparkles className="h-3 w-3" /> : <Zap className="h-3 w-3" />}
            {sourceLabel(source)}
          </Badge>
        )}
        {type === 'yes_no' ? (
          <div className="flex gap-2 mt-1">
            <Button type="button" variant={value === 'Yes' ? 'default' : 'outline'} size="sm"
              onClick={() => updateAnswer(key, 'Yes')} className="flex-1">Yes</Button>
            <Button type="button" variant={value === 'No' ? 'default' : 'outline'} size="sm"
              onClick={() => updateAnswer(key, 'No')} className="flex-1">No</Button>
          </div>
        ) : type === 'select' && q.options?.length ? (
          <Select value={value} onChange={e => updateAnswer(key, e.target.value)} className="mt-1">
            <option value="">Select an option...</option>
            {q.options.map(opt => <option key={opt} value={opt}>{opt}</option>)}
          </Select>
        ) : (
          <Input value={value} onChange={e => updateAnswer(key, e.target.value)}
            className="mt-1" placeholder={q.placeholder || 'Your answer...'} />
        )}
        {error && <p className="text-xs text-destructive flex items-center gap-1"><AlertCircle className="h-3 w-3" />{error}</p>}
      </div>
    )
  }

  function timeAgo(dateStr: string) {
    const diff = Date.now() - new Date(dateStr).getTime()
    const days = Math.floor(diff / 86400000)
    if (days === 0) return 'Today'; if (days === 1) return '1 day ago'
    if (days < 30) return `${days} days ago`; return `${Math.floor(days / 30)} months ago`
  }

  if (loading) return <div className="flex items-center justify-center py-16"><div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" /></div>
  if (!job) return <div className="py-16 text-center"><Briefcase className="mx-auto mb-3 h-10 w-10 opacity-30" /><p className="text-muted-foreground">Job not found</p><Button variant="ghost" className="mt-4" onClick={() => navigate('/candidate/jobs')}>Back to jobs</Button></div>

  return (
    <div className="space-y-6 max-w-3xl">
      <Button variant="ghost" size="sm" onClick={() => navigate('/candidate/jobs')} className="gap-1">
        <ArrowLeft className="h-4 w-4" /> Back to jobs
      </Button>

      {/* Job header */}
      <Card>
        <CardContent className="p-6">
          <div className="flex flex-col gap-4 sm:flex-row sm:items-start sm:justify-between">
            <div>
              <h1 className="font-heading text-2xl font-bold mb-2">{job.title}</h1>
              <div className="flex flex-wrap items-center gap-3 text-sm text-muted-foreground">
                <span className="flex items-center gap-1"><Building2 className="h-4 w-4" />{job.company || job.poster_company || 'Company'}</span>
                {job.location && <span className="flex items-center gap-1"><MapPin className="h-4 w-4" />{job.location}</span>}
                {job.salary_range && <span className="flex items-center gap-1"><DollarSign className="h-4 w-4" />{job.salary_range}</span>}
                {job.job_type && <Badge variant="secondary">{job.job_type}</Badge>}
                <span className="flex items-center gap-1 text-xs"><Clock className="h-3 w-3" />Posted {timeAgo(job.created_at)}</span>
              </div>
            </div>
            {applied ? (
              <Badge variant="success" className="gap-1 text-sm py-1.5 px-3 shrink-0"><CheckCircle className="h-3.5 w-3.5" /> Applied</Badge>
            ) : user ? (
              <Button onClick={() => setShowApplyForm(!showApplyForm)} className="gap-2 shrink-0"><Send className="h-4 w-4" /> Apply Now</Button>
            ) : (
              <Button onClick={() => navigate('/login')} className="gap-2 shrink-0">Sign in to Apply</Button>
            )}
          </div>
        </CardContent>
      </Card>

      {/* Apply form with AI features */}
      {showApplyForm && !applied && (
        <Card className="border-primary/30 shadow-lg">
          <CardHeader>
            <CardTitle className="flex items-center gap-2"><Send className="h-5 w-5" />Apply for {job.title}</CardTitle>
          </CardHeader>
          <CardContent className="space-y-5">
            {/* Auto-fill banner */}
            {autoFill && Object.keys(autoFillSources).length > 0 && (
              <div className="rounded-lg bg-blue-50 border border-blue-200 p-3 text-sm text-blue-800 flex items-center gap-2">
                <Zap className="h-4 w-4 shrink-0" />
                Some fields were auto-filled from your profile and past applications. Review and update as needed.
              </div>
            )}

            {/* Cover letter */}
            <div>
              <div className="flex items-center justify-between mb-1">
                <Label>Cover Letter <span className="text-muted-foreground text-xs">(optional)</span></Label>
                <Button variant="outline" size="sm" onClick={generateCoverLetter} disabled={generatingCL} className="gap-1 text-xs">
                  {generatingCL ? <Loader2 className="h-3 w-3 animate-spin" /> : <Sparkles className="h-3 w-3" />}
                  {generatingCL ? 'Generating...' : '✨ Generate with AI'}
                </Button>
              </div>
              <Textarea
                placeholder="Tell the employer why you're a great fit for this role..."
                value={coverLetter} onChange={e => setCoverLetter(e.target.value)}
                rows={6} className="mt-1"
              />
              {coverLetter && autoFill?.cover_letter && coverLetter === autoFill.cover_letter && (
                <p className="text-xs text-muted-foreground mt-1 flex items-center gap-1">
                  <Zap className="h-3 w-3" /> From your last application — personalize it for this role
                </p>
              )}
            </div>

            {/* Screening questions */}
            {screeningQuestions.length > 0 && (
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <ListChecks className="h-4 w-4 text-primary" />
                    <h4 className="font-medium text-sm">Pre-screening Questions</h4>
                  </div>
                  <Button variant="outline" size="sm" onClick={getSuggestions} disabled={generatingSuggestions} className="gap-1 text-xs">
                    {generatingSuggestions ? <Loader2 className="h-3 w-3 animate-spin" /> : <Wand2 className="h-3 w-3" />}
                    {generatingSuggestions ? 'Suggesting...' : '✨ AI Suggest Answers'}
                  </Button>
                </div>
                {screeningQuestions.map((q, i) => (
                  <div key={q.id || i} className="rounded-lg border p-4 space-y-1">
                    <Label className="text-sm font-medium">
                      {q.question || ''}{q.required && <span className="text-destructive ml-1">*</span>}
                    </Label>
                    {q.category && <p className="text-xs text-muted-foreground capitalize">{q.category.replace(/_/g, ' ')}</p>}
                    {renderScreeningInput(q, i)}
                  </div>
                ))}
              </div>
            )}

            <div className="flex gap-2 pt-2 border-t">
              <Button onClick={handleApply} disabled={applying} className="gap-2">
                {applying ? <div className="h-4 w-4 animate-spin rounded-full border-2 border-white border-t-transparent" /> : <Send className="h-4 w-4" />}
                Submit Application
              </Button>
              <Button variant="outline" onClick={() => setShowApplyForm(false)}>Cancel</Button>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Description */}
      <Card>
        <CardHeader><CardTitle className="flex items-center gap-2"><Briefcase className="h-5 w-5" /> Job Description</CardTitle></CardHeader>
        <CardContent>
          <div className="prose prose-sm max-w-none whitespace-pre-wrap text-sm leading-relaxed">{job.description || 'No description provided.'}</div>
        </CardContent>
      </Card>

      {/* Requirements */}
      {job.requirements && (
        <Card>
          <CardHeader><CardTitle className="flex items-center gap-2"><FileText className="h-5 w-5" /> Requirements</CardTitle></CardHeader>
          <CardContent>
            <div className="prose prose-sm max-w-none whitespace-pre-wrap text-sm leading-relaxed">{job.requirements}</div>
          </CardContent>
        </Card>
      )}

      {screeningQuestions.length > 0 && !showApplyForm && !applied && (
        <div className="rounded-lg bg-muted/50 p-4 text-sm text-muted-foreground flex items-center gap-2">
          <ListChecks className="h-4 w-4 shrink-0" />
          This job has {screeningQuestions.length} pre-screening question{screeningQuestions.length > 1 ? 's' : ''} you'll need to answer when applying.
        </div>
      )}
    </div>
  )
}

import { useEffect, useState } from 'react'
import { Link } from 'react-router-dom'
import { apiCall } from '@/lib/api'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Dialog, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog'
import {
  FileText, Building2, MapPin, Calendar, ExternalLink, XCircle, AlertTriangle,
  Clock, CheckCircle, Briefcase, DollarSign, Filter, ClipboardList,
  ArrowRight, Eye,
} from 'lucide-react'

interface ScreeningQuestion {
  question: string
  type: 'text' | 'yes_no' | 'select'
  required?: boolean
  options?: string[]
  category?: string
}

interface Application {
  id: number
  job_id: number
  status: string
  title: string
  company: string
  location: string
  salary_range: string
  job_type: string
  posted_by_company?: string
  applied_at: string
  updated_at: string
  match_score?: number
  cover_letter?: string
  screening_answers?: string | Record<string, string>
  screening_questions?: string | ScreeningQuestion[]
}

const statusConfig: Record<string, { label: string; variant: 'default' | 'secondary' | 'success' | 'warning' | 'destructive'; icon: typeof Clock }> = {
  applied: { label: 'Applied', variant: 'secondary', icon: FileText },
  screening: { label: 'Screening', variant: 'default', icon: Eye },
  shortlisted: { label: 'Shortlisted', variant: 'default', icon: CheckCircle },
  reviewing: { label: 'Under Review', variant: 'warning', icon: Eye },
  interviewed: { label: 'Interviewed', variant: 'default', icon: Briefcase },
  offered: { label: 'Offer Received', variant: 'success', icon: DollarSign },
  hired: { label: 'Hired', variant: 'success', icon: CheckCircle },
  rejected: { label: 'Not Selected', variant: 'destructive', icon: XCircle },
  withdrawn: { label: 'Withdrawn', variant: 'secondary', icon: XCircle },
}

export function CandidateApplicationsPage() {
  const [applications, setApplications] = useState<Application[]>([])
  const [loading, setLoading] = useState(true)
  const [statusFilter, setStatusFilter] = useState('')
  const [withdrawTarget, setWithdrawTarget] = useState<Application | null>(null)
  const [withdrawing, setWithdrawing] = useState(false)
  const [selectedApp, setSelectedApp] = useState<Application | null>(null)

  useEffect(() => {
    loadApplications()
  }, [])

  async function loadApplications() {
    try {
      const data = await apiCall<{ success: boolean; applications: Application[] }>('/candidate/applications')
      setApplications(data.applications || [])
    } catch {
      // silent
    } finally {
      setLoading(false)
    }
  }

  async function withdrawApplication() {
    if (!withdrawTarget) return
    setWithdrawing(true)
    try {
      await apiCall(`/candidate/applications/${withdrawTarget.id}/withdraw`, {
        method: 'PUT',
      })
      setApplications(prev =>
        prev.map(a => a.id === withdrawTarget.id ? { ...a, status: 'withdrawn' } : a)
      )
      setWithdrawTarget(null)
      setSelectedApp(null)
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Failed to withdraw application')
    } finally {
      setWithdrawing(false)
    }
  }

  function timeAgo(dateStr: string) {
    const diff = Date.now() - new Date(dateStr).getTime()
    const days = Math.floor(diff / 86400000)
    if (days === 0) return 'Today'
    if (days === 1) return 'Yesterday'
    if (days < 7) return `${days} days ago`
    if (days < 30) return `${Math.floor(days / 7)} weeks ago`
    return `${Math.floor(days / 30)} months ago`
  }

  function parseScreeningData(app: Application) {
    try {
      const answers = typeof app.screening_answers === 'string'
        ? JSON.parse(app.screening_answers)
        : app.screening_answers
      const questions: ScreeningQuestion[] = typeof app.screening_questions === 'string'
        ? JSON.parse(app.screening_questions)
        : (app.screening_questions || [])
      return { answers, questions }
    } catch {
      return { answers: null, questions: [] }
    }
  }

  const statuses = ['applied', 'screening', 'shortlisted', 'reviewing', 'interviewed', 'offered', 'hired', 'rejected', 'withdrawn']
  const statusCounts = statuses.reduce((acc, s) => {
    acc[s] = applications.filter(a => a.status === s).length
    return acc
  }, {} as Record<string, number>)

  const filtered = applications.filter(a => !statusFilter || a.status === statusFilter)

  const active = filtered.filter(a => !['rejected', 'withdrawn', 'hired'].includes(a.status))
  const completed = filtered.filter(a => ['rejected', 'withdrawn', 'hired'].includes(a.status))

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-heading text-2xl font-bold">My Applications</h1>
        <p className="text-muted-foreground">Track your job application status and manage active applications</p>
      </div>

      {/* Stats */}
      <div className="grid gap-3 sm:grid-cols-4">
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold">{applications.length}</p>
            <p className="text-xs text-muted-foreground">Total Applied</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-blue-600">
              {applications.filter(a => !['rejected', 'withdrawn', 'hired'].includes(a.status)).length}
            </p>
            <p className="text-xs text-muted-foreground">Active</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-amber-600">
              {applications.filter(a => ['reviewing', 'interviewed'].includes(a.status)).length}
            </p>
            <p className="text-xs text-muted-foreground">In Progress</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-emerald-600">
              {applications.filter(a => ['offered', 'hired'].includes(a.status)).length}
            </p>
            <p className="text-xs text-muted-foreground">Offers / Hired</p>
          </CardContent>
        </Card>
      </div>

      {/* Status filter pills */}
      <div className="flex flex-wrap gap-2">
        <Button
          variant={!statusFilter ? 'default' : 'outline'}
          size="sm"
          onClick={() => setStatusFilter('')}
        >
          All ({applications.length})
        </Button>
        {statuses.map(s => (
          statusCounts[s] > 0 ? (
            <Button
              key={s}
              variant={statusFilter === s ? 'default' : 'outline'}
              size="sm"
              onClick={() => setStatusFilter(s)}
            >
              {statusConfig[s]?.label || s} ({statusCounts[s]})
            </Button>
          ) : null
        ))}
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-16">
          <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
        </div>
      ) : applications.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <FileText className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground mb-4">You haven't applied to any jobs yet</p>
            <Link to="/candidate/jobs">
              <Button>Browse Jobs</Button>
            </Link>
          </CardContent>
        </Card>
      ) : filtered.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <Filter className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground">No applications match this filter</p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-6">
          {active.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">Active Applications ({active.length})</h2>
              <div className="space-y-3">
                {active.map(app => (
                  <ApplicationCard
                    key={app.id}
                    app={app}
                    timeAgo={timeAgo}
                    onWithdraw={() => setWithdrawTarget(app)}
                    onClick={() => setSelectedApp(app)}
                  />
                ))}
              </div>
            </div>
          )}

          {completed.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">Completed ({completed.length})</h2>
              <div className="space-y-3">
                {completed.map(app => (
                  <ApplicationCard
                    key={app.id}
                    app={app}
                    timeAgo={timeAgo}
                    onClick={() => setSelectedApp(app)}
                  />
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {/* Application detail dialog */}
      {selectedApp && (
        <Dialog open={true} onClose={() => setSelectedApp(null)} className="max-w-lg">
          <DialogHeader>
            <DialogTitle>{selectedApp.title}</DialogTitle>
            <DialogDescription>
              {selectedApp.company || selectedApp.posted_by_company || 'Company'}
              {selectedApp.location ? ` • ${selectedApp.location}` : ''}
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            {/* Status badge */}
            {(() => {
              const config = statusConfig[selectedApp.status] || { label: selectedApp.status, variant: 'secondary' as const, icon: Clock }
              return <Badge variant={config.variant} className="w-fit">{config.label}</Badge>
            })()}

            {/* Details grid */}
            <div className="grid grid-cols-2 gap-3">
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <Calendar className="h-3 w-3" /> Applied
                </p>
                <p className="font-medium">{new Date(selectedApp.applied_at).toLocaleDateString()}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <Clock className="h-3 w-3" /> Last Update
                </p>
                <p className="font-medium">{timeAgo(selectedApp.updated_at)}</p>
              </div>
              {selectedApp.salary_range && (
                <div className="rounded-lg bg-muted/50 p-3">
                  <p className="text-xs text-muted-foreground flex items-center gap-1">
                    <DollarSign className="h-3 w-3" /> Salary
                  </p>
                  <p className="font-medium">{selectedApp.salary_range}</p>
                </div>
              )}
              {selectedApp.match_score && (
                <div className="rounded-lg bg-muted/50 p-3">
                  <p className="text-xs text-muted-foreground">Match Score</p>
                  <p className="font-medium text-primary">{selectedApp.match_score}%</p>
                </div>
              )}
            </div>

            {/* Progress timeline */}
            <ApplicationTimeline status={selectedApp.status} appliedAt={selectedApp.applied_at} updatedAt={selectedApp.updated_at} />

            {/* Cover letter */}
            {selectedApp.cover_letter && (
              <div>
                <h4 className="font-medium text-sm mb-1">Your Cover Letter</h4>
                <div className="rounded-lg bg-muted/50 p-3 text-sm whitespace-pre-wrap max-h-40 overflow-y-auto">
                  {selectedApp.cover_letter}
                </div>
              </div>
            )}

            {/* Screening answers */}
            <ScreeningAnswersSection app={selectedApp} parseScreeningData={parseScreeningData} />

            {/* Actions */}
            <div className="flex gap-2 pt-2">
              <Link to={`/candidate/jobs/${selectedApp.job_id}`} className="flex-1">
                <Button variant="outline" className="gap-2 w-full">
                  <ExternalLink className="h-4 w-4" /> View Job
                </Button>
              </Link>
              {!['rejected', 'withdrawn', 'hired'].includes(selectedApp.status) && (
                <Button
                  variant="outline"
                  onClick={() => {
                    setSelectedApp(null)
                    setWithdrawTarget(selectedApp)
                  }}
                  className="gap-2 text-destructive hover:text-destructive"
                >
                  <XCircle className="h-4 w-4" /> Withdraw
                </Button>
              )}
            </div>
          </div>
        </Dialog>
      )}

      {/* Withdraw confirmation dialog */}
      {withdrawTarget && (
        <Dialog open={true} onClose={() => !withdrawing && setWithdrawTarget(null)} className="max-w-md">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <AlertTriangle className="h-5 w-5 text-amber-500" />
              Withdraw Application?
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <p className="text-sm text-muted-foreground">
              Are you sure you want to withdraw your application for{' '}
              <strong>{withdrawTarget.title}</strong> at{' '}
              <strong>{withdrawTarget.company || withdrawTarget.posted_by_company || 'this company'}</strong>?
            </p>
            <div className="rounded-lg bg-amber-50 border border-amber-200 p-3 text-sm text-amber-800">
              This action cannot be undone. You may need to reapply if you change your mind.
            </div>
            <div className="flex gap-2 pt-2">
              <Button
                variant="outline"
                onClick={() => setWithdrawTarget(null)}
                disabled={withdrawing}
                className="flex-1"
              >
                Keep Application
              </Button>
              <Button
                variant="destructive"
                onClick={withdrawApplication}
                disabled={withdrawing}
                className="gap-2 flex-1"
              >
                {withdrawing ? (
                  <div className="h-4 w-4 animate-spin rounded-full border-2 border-white border-t-transparent" />
                ) : (
                  <XCircle className="h-4 w-4" />
                )}
                Withdraw
              </Button>
            </div>
          </div>
        </Dialog>
      )}
    </div>
  )
}

function ScreeningAnswersSection({
  app,
  parseScreeningData,
}: {
  app: Application
  parseScreeningData: (app: Application) => { answers: Record<string, string> | null; questions: ScreeningQuestion[] }
}) {
  const { answers, questions } = parseScreeningData(app)

  if (!answers || Object.keys(answers).length === 0) return null

  return (
    <div>
      <h4 className="font-medium text-sm mb-2 flex items-center gap-1.5">
        <ClipboardList className="h-4 w-4 text-primary" />
        Your Screening Answers
      </h4>
      <div className="space-y-2">
        {Object.entries(answers).map(([key, value], i) => {
          const q = questions[i]
          const questionText = q?.question || q || `Question ${i + 1}`
          return (
            <div key={key} className="rounded-lg bg-muted/50 p-3">
              <p className="text-xs text-muted-foreground mb-1 font-medium">
                {String(questionText)}
              </p>
              <p className="text-sm">{String(value)}</p>
            </div>
          )
        })}
      </div>
    </div>
  )
}

function ApplicationTimeline({ status, appliedAt, updatedAt }: { status: string; appliedAt: string; updatedAt: string }) {
  const steps = [
    { key: 'applied', label: 'Applied', icon: FileText },
    { key: 'screening', label: 'Screening', icon: Eye },
    { key: 'interviewed', label: 'Interview', icon: Briefcase },
    { key: 'offered', label: 'Offer', icon: CheckCircle },
  ]

  const stepIndex = {
    applied: 0, screening: 1, shortlisted: 1, reviewing: 1, interviewed: 2,
    offered: 3, hired: 4, rejected: -1, withdrawn: -1,
  }[status] ?? 0

  // Special terminal states
  if (status === 'rejected' || status === 'withdrawn') {
    const config = statusConfig[status]
    return (
      <div>
        <h4 className="font-medium text-sm mb-3">Status Timeline</h4>
        <div className="space-y-3">
          <div className="flex items-center gap-3">
            <div className="flex h-8 w-8 items-center justify-center rounded-full border-2 border-primary bg-primary/10">
              <FileText className="h-4 w-4 text-primary" />
            </div>
            <div>
              <p className="text-sm font-medium">Applied</p>
              <p className="text-xs text-muted-foreground">{new Date(appliedAt).toLocaleDateString()}</p>
            </div>
          </div>
          <div className="ml-4 h-4 w-px bg-muted" />
          <div className="flex items-center gap-3">
            <div className={`flex h-8 w-8 items-center justify-center rounded-full border-2 ${
              status === 'rejected' ? 'border-destructive bg-destructive/10' : 'border-muted bg-muted/50'
            }`}>
              <XCircle className={`h-4 w-4 ${status === 'rejected' ? 'text-destructive' : 'text-muted-foreground'}`} />
            </div>
            <div>
              <p className="text-sm font-medium">{config.label}</p>
              <p className="text-xs text-muted-foreground">{new Date(updatedAt).toLocaleDateString()}</p>
            </div>
          </div>
        </div>
      </div>
    )
  }

  if (stepIndex < 0) return null

  return (
    <div>
      <h4 className="font-medium text-sm mb-3">Progress</h4>
      <div className="flex items-center gap-1">
        {steps.map((step, i) => {
          const isComplete = i <= stepIndex
          const isCurrent = i === stepIndex
          const Icon = step.icon
          return (
            <div key={step.key} className="flex items-center gap-1 flex-1">
              <div className={`flex items-center gap-1.5 ${isComplete ? 'text-primary' : 'text-muted-foreground/50'}`}>
                <div className={`flex h-7 w-7 items-center justify-center rounded-full border-2 transition-all ${
                  isCurrent ? 'border-primary bg-primary text-white' :
                  isComplete ? 'border-primary bg-primary/10' : 'border-muted'
                }`}>
                  <Icon className="h-3.5 w-3.5" />
                </div>
                <span className="text-[11px] font-medium hidden sm:inline">{step.label}</span>
              </div>
              {i < steps.length - 1 && (
                <div className={`h-0.5 flex-1 mx-1 ${i < stepIndex ? 'bg-primary' : 'bg-muted'}`} />
              )}
            </div>
          )
        })}
      </div>
      {/* Date labels */}
      <div className="flex justify-between mt-2 px-1">
        <span className="text-[10px] text-muted-foreground">
          {new Date(appliedAt).toLocaleDateString()}
        </span>
        {stepIndex > 0 && (
          <span className="text-[10px] text-muted-foreground">
            Updated {new Date(updatedAt).toLocaleDateString()}
          </span>
        )}
      </div>
    </div>
  )
}

function ApplicationCard({
  app,
  timeAgo,
  onWithdraw,
  onClick,
}: {
  app: Application
  timeAgo: (d: string) => string
  onWithdraw?: () => void
  onClick?: () => void
}) {
  const config = statusConfig[app.status] || { label: app.status, variant: 'secondary' as const, icon: Clock }

  // Progress steps (aligned with pipeline stages)
  const steps = ['Applied', 'Screening', 'Interview', 'Offer']
  const currentStep = {
    applied: 0, screening: 1, shortlisted: 1, reviewing: 1, interviewed: 2,
    offered: 3, hired: 4, rejected: -1, withdrawn: -1,
  }[app.status] ?? 0

  // Check if has screening answers
  let hasScreening = false
  try {
    const answers = typeof app.screening_answers === 'string' ? JSON.parse(app.screening_answers) : app.screening_answers
    hasScreening = answers && Object.keys(answers).length > 0
  } catch { /* ignore */ }

  return (
    <Card
      className="cursor-pointer transition-shadow hover:shadow-md"
      onClick={onClick}
    >
      <CardContent className="p-4">
        <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
          <div className="min-w-0 flex-1">
            <div className="flex items-center gap-2 mb-1">
              <h3 className="font-semibold truncate">{app.title}</h3>
              <Badge variant={config.variant}>{config.label}</Badge>
              {hasScreening && (
                <Badge variant="outline" className="gap-1 text-[10px]">
                  <ClipboardList className="h-3 w-3" /> Screening
                </Badge>
              )}
            </div>
            <div className="flex flex-wrap items-center gap-3 text-sm text-muted-foreground">
              <span className="flex items-center gap-1">
                <Building2 className="h-3.5 w-3.5" />
                {app.company || app.posted_by_company || 'Company'}
              </span>
              {app.location && (
                <span className="flex items-center gap-1">
                  <MapPin className="h-3.5 w-3.5" />
                  {app.location}
                </span>
              )}
              <span className="flex items-center gap-1">
                <Calendar className="h-3.5 w-3.5" />
                Applied {timeAgo(app.applied_at)}
              </span>
              {app.salary_range && (
                <span className="flex items-center gap-1">
                  <DollarSign className="h-3.5 w-3.5" />
                  {app.salary_range}
                </span>
              )}
            </div>

            {/* Progress timeline */}
            {currentStep >= 0 && (
              <div className="mt-3 flex items-center gap-1">
                {steps.map((step, i) => (
                  <div key={step} className="flex items-center gap-1">
                    <div className={`h-2 w-2 rounded-full ${
                      i === currentStep ? 'bg-primary ring-2 ring-primary/30' :
                      i < currentStep ? 'bg-primary' : 'bg-muted'
                    }`} />
                    <span className={`text-[10px] ${i <= currentStep ? 'text-foreground' : 'text-muted-foreground'}`}>
                      {step}
                    </span>
                    {i < steps.length - 1 && (
                      <div className={`h-px w-4 ${i < currentStep ? 'bg-primary' : 'bg-muted'}`} />
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
          <div className="flex items-center gap-2 shrink-0">
            {onWithdraw && !['rejected', 'withdrawn', 'hired'].includes(app.status) && (
              <Button
                variant="ghost"
                size="sm"
                onClick={e => {
                  e.stopPropagation()
                  onWithdraw()
                }}
                className="gap-1 text-muted-foreground hover:text-destructive"
              >
                <XCircle className="h-3.5 w-3.5" /> Withdraw
              </Button>
            )}
            <Link
              to={`/candidate/jobs/${app.job_id}`}
              onClick={e => e.stopPropagation()}
            >
              <Button variant="ghost" size="sm" className="gap-1 shrink-0">
                View Job <ExternalLink className="h-3 w-3" />
              </Button>
            </Link>
          </div>
        </div>
      </CardContent>
    </Card>
  )
}

import { useEffect, useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import { apiCall } from '@/lib/api'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Input } from '@/components/ui/input'
import { Select } from '@/components/ui/select'
import {
  Plus, Briefcase, MapPin, Users, Edit, Trash2, Search, Eye, EyeOff,
  BarChart3, Clock,
} from 'lucide-react'

interface Job {
  id: number
  title: string
  company: string
  location: string
  salary_range: string
  job_type: string
  status: string
  created_at: string
  views?: number
  application_count?: number
  interviews?: number
  screening_questions?: string
}

const statusColors: Record<string, 'success' | 'warning' | 'secondary' | 'destructive'> = {
  active: 'success',
  paused: 'warning',
  closed: 'secondary',
  draft: 'secondary',
}

export function RecruiterJobsPage() {
  const navigate = useNavigate()
  const [jobs, setJobs] = useState<Job[]>([])
  const [loading, setLoading] = useState(true)
  const [deleting, setDeleting] = useState<number | null>(null)
  const [search, setSearch] = useState('')
  const [statusFilter, setStatusFilter] = useState('')

  useEffect(() => {
    loadJobs()
  }, [])

  async function loadJobs() {
    try {
      const data = await apiCall<{ jobs: Job[] }>('/recruiter/jobs')
      setJobs(data.jobs || [])
    } catch {
      // silent
    } finally {
      setLoading(false)
    }
  }

  async function toggleJobStatus(job: Job) {
    const newStatus = job.status === 'active' ? 'paused' : 'active'
    try {
      await apiCall(`/recruiter/jobs/${job.id}`, {
        method: 'PUT',
        body: { status: newStatus },
      })
      loadJobs()
    } catch {
      // silent
    }
  }

  async function deleteJob(id: number) {
    if (!confirm('Are you sure you want to delete this job posting?')) return
    setDeleting(id)
    try {
      await apiCall(`/jobs/${id}`, { method: 'DELETE' })
      loadJobs()
    } catch {
      // silent
    } finally {
      setDeleting(null)
    }
  }

  function timeAgo(dateStr: string) {
    const diff = Date.now() - new Date(dateStr).getTime()
    const days = Math.floor(diff / 86400000)
    if (days === 0) return 'Today'
    if (days === 1) return '1 day ago'
    if (days < 30) return `${days} days ago`
    return `${Math.floor(days / 30)}mo ago`
  }

  const filtered = jobs.filter(j => {
    const matchSearch = !search ||
      j.title?.toLowerCase().includes(search.toLowerCase()) ||
      j.location?.toLowerCase().includes(search.toLowerCase())
    const matchStatus = !statusFilter || j.status === statusFilter
    return matchSearch && matchStatus
  })

  const activeJobs = jobs.filter(j => j.status === 'active')
  const totalApps = jobs.reduce((sum, j) => sum + (j.application_count || 0), 0)

  return (
    <div className="space-y-6">
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h1 className="font-heading text-2xl font-bold">Job Postings</h1>
          <p className="text-muted-foreground text-sm">Manage your job listings</p>
        </div>
        <Link to="/recruiter/jobs/new">
          <Button className="gap-2">
            <Plus className="h-4 w-4" /> Post New Job
          </Button>
        </Link>
      </div>

      {/* Stats */}
      <div className="grid gap-3 grid-cols-3">
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-emerald-600">{activeJobs.length}</p>
            <p className="text-xs text-muted-foreground">Active</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold">{jobs.length}</p>
            <p className="text-xs text-muted-foreground">Total</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-blue-600">{totalApps}</p>
            <p className="text-xs text-muted-foreground">Applications</p>
          </CardContent>
        </Card>
      </div>

      {/* Filters */}
      {jobs.length > 0 && (
        <div className="flex flex-col gap-3 sm:flex-row">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
            <Input
              placeholder="Search jobs by title or location..."
              value={search}
              onChange={e => setSearch(e.target.value)}
              className="pl-9"
            />
          </div>
          <Select
            value={statusFilter}
            onChange={e => setStatusFilter(e.target.value)}
            className="sm:w-36"
          >
            <option value="">All Status</option>
            <option value="active">Active</option>
            <option value="paused">Paused</option>
            <option value="closed">Closed</option>
            <option value="draft">Draft</option>
          </Select>
        </div>
      )}

      {loading ? (
        <div className="flex items-center justify-center py-16">
          <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
        </div>
      ) : jobs.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <Briefcase className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground mb-4">No job postings yet</p>
            <Link to="/recruiter/jobs/new">
              <Button className="gap-2"><Plus className="h-4 w-4" /> Create Your First Job</Button>
            </Link>
          </CardContent>
        </Card>
      ) : filtered.length === 0 ? (
        <Card>
          <CardContent className="py-12 text-center">
            <Search className="mx-auto mb-3 h-8 w-8 opacity-30" />
            <p className="text-muted-foreground">No jobs match your filters</p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-3">
          {filtered.map(job => (
            <Card key={job.id} className="transition-shadow hover:shadow-sm">
              <CardContent className="p-4">
                <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
                  <div className="min-w-0 flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <h3 className="font-semibold truncate">{job.title}</h3>
                      <Badge variant={statusColors[job.status] || 'secondary'}>
                        {job.status}
                      </Badge>
                    </div>
                    <div className="flex flex-wrap items-center gap-3 text-sm text-muted-foreground">
                      {job.location && (
                        <span className="flex items-center gap-1">
                          <MapPin className="h-3.5 w-3.5" /> {job.location}
                        </span>
                      )}
                      {job.job_type && <span>{job.job_type}</span>}
                      {job.salary_range && <span>{job.salary_range}</span>}
                      <span className="flex items-center gap-1">
                        <Users className="h-3.5 w-3.5" /> {job.application_count || 0} applicants
                      </span>
                      <span className="flex items-center gap-1 text-xs">
                        <Clock className="h-3 w-3" /> {timeAgo(job.created_at)}
                      </span>
                    </div>
                  </div>
                  <div className="flex items-center gap-1 shrink-0">
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => navigate(`/recruiter/jobs/${job.id}/applicants`)}
                      className="gap-1"
                      title="View applicants"
                    >
                      <Users className="h-3.5 w-3.5" />
                      <span className="text-xs">{job.application_count || 0}</span>
                    </Button>
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => navigate(`/recruiter/jobs/${job.id}/edit`)}
                      title="Edit job"
                    >
                      <Edit className="h-3.5 w-3.5" />
                    </Button>
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => toggleJobStatus(job)}
                      title={job.status === 'active' ? 'Pause job' : 'Activate job'}
                    >
                      {job.status === 'active' ? (
                        <EyeOff className="h-3.5 w-3.5" />
                      ) : (
                        <Eye className="h-3.5 w-3.5" />
                      )}
                    </Button>
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => deleteJob(job.id)}
                      disabled={deleting === job.id}
                      className="text-destructive hover:text-destructive"
                      title="Delete job"
                    >
                      <Trash2 className="h-3.5 w-3.5" />
                    </Button>
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  )
}

