    69→  const [titleError, setTitleError] = useState('')
    70→  const [aiSuggestingQuestions, setAiSuggestingQuestions] = useState(false)
    71→  const [questionBank, setQuestionBank] = useState<ScreeningQuestion[]>([])
    72→  const [showQuestionBank, setShowQuestionBank] = useState(false)
