    77→  const [aiSuggestingSkills, setAiSuggestingSkills] = useState(false)
    78→  const [aiSuggestingTitles, setAiSuggestingTitles] = useState(false)
    79→  const [titleSuggestions, setTitleSuggestions] = useState<TitleSuggestion[]>([])
