   371→  }
   372→
   373→  function removeOption(qIndex: number, optIndex: number) {
   374→    setScreeningQuestions(prev => prev.map((q, i) =>
   375→      i === qIndex ? { ...q, options: (q.options || []).filter((_, j) => j !== optIndex) } : q
   376→    ))
   377→  }
   378→
   379→  if (loading) {
   380→    return (
   381→      <div className="flex items-center justify-center py-16">
   382→        <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
   383→      </div>
   384→    )
   385→  }
   386→
   387→  return (
   388→    <div className="max-w-2xl space-y-6">
   389→      {/* AI Success Toast */}
   390→      {aiSuccess && (
   391→        <div className="fixed top-4 right-4 z-50 animate-in fade-in slide-in-from-top-2 bg-green-600 text-white px-4 py-2 rounded-lg shadow-lg flex items-center gap-2 text-sm">
   392→          <CheckCircle2 className="h-4 w-4" />
   393→          {aiSuccess}
   394→        </div>
   395→      )}
   396→
   397→      <div className="flex items-center gap-3">
   398→        <Button variant="ghost" size="sm" onClick={() => navigate('/recruiter/jobs')}>
   399→          <ArrowLeft className="h-4 w-4" />
   400→        </Button>
   401→        <div>
   402→          <h1 className="font-heading text-2xl font-bold">
   403→            {isEdit ? 'Edit Job' : 'Post New Job'}
   404→          </h1>
   405→          <p className="text-muted-foreground text-sm">
   406→            {isEdit ? 'Update your job listing' : 'Create a new job posting'}
   407→          </p>
   408→        </div>
   409→      </div>
   410→
   411→      {/* Job details */}
   412→      <Card>
   413→        <CardHeader>
   414→          <CardTitle className="flex items-center gap-2">
   415→            <Briefcase className="h-5 w-5" /> Job Details
   416→          </CardTitle>
   417→        </CardHeader>
   418→        <CardContent className="space-y-4">
   419→          <div>
   420→            <div className="flex items-center justify-between">
   421→              <Label>Job Title *</Label>
   422→              <Button
