   853→                                size="icon"
   854→                                className="h-8 w-8 shrink-0"
   855→                                onClick={() => removeOption(i, oi)}
   856→                              >
   857→                                <X className="h-3 w-3" />
   858→                              </Button>
   859→                            </div>
   860→                          ))}
   861→                          <Button
   862→                            variant="ghost"
   863→                            size="sm"
   864→                            onClick={() => addOption(i)}
   865→                            className="text-xs gap-1"
   866→                          >
