import { useEffect, useState } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { apiCall } from '@/lib/api'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { Select } from '@/components/ui/select'
import { Badge } from '@/components/ui/badge'
import {
  ArrowLeft, Save, Plus, X, Briefcase, ListChecks, GripVertical, AlertCircle, Sparkles,
  Wand2, Lightbulb, Loader2, CheckCircle2, ChevronDown, ChevronUp,
} from 'lucide-react'

interface TitleSuggestion {
  title: string
  reason: string
  search_volume?: string
  seniority_match?: string
}

interface SkillSuggestion {
  skill: string
  category: string
  importance: string
}

interface ScreeningQuestion {
  id?: string
  question: string
  type: 'text' | 'yes_no' | 'select'
  required: boolean
  options?: string[]
  placeholder?: string
  category?: string
}

const defaultQuestionTemplates: ScreeningQuestion[] = [
  { question: 'Are you legally authorized to work in this country?', type: 'yes_no', required: true, category: 'work_authorization' },
  { question: 'What are your salary expectations? (annual, USD)', type: 'text', required: false, placeholder: 'e.g. $80,000 - $100,000', category: 'salary' },
  { question: 'When can you start?', type: 'select', required: true, options: ['Immediately', 'Within 2 weeks', 'Within 1 month', 'More than 1 month'], category: 'availability' },
  { question: 'Are you willing to relocate for this position?', type: 'yes_no', required: false, category: 'relocation' },
  { question: 'How many years of relevant experience do you have?', type: 'select', required: true, options: ['0-1 years', '1-3 years', '3-5 years', '5-10 years', '10+ years'], category: 'experience' },
]

const typeLabels: Record<string, string> = {
  text: 'Text',
  yes_no: 'Yes / No',
  select: 'Dropdown',
}

export function RecruiterJobFormPage() {
  const { id } = useParams()
  const navigate = useNavigate()
  const isEdit = !!id
  const [loading, setLoading] = useState(isEdit)
  const [saving, setSaving] = useState(false)

  const [title, setTitle] = useState('')
  const [company, setCompany] = useState('')
  const [description, setDescription] = useState('')
  const [requirements, setRequirements] = useState('')
  const [location, setLocation] = useState('')
  const [salaryRange, setSalaryRange] = useState('')
  const [jobType, setJobType] = useState('full-time')
  const [screeningQuestions, setScreeningQuestions] = useState<ScreeningQuestion[]>([])
  const [showTemplates, setShowTemplates] = useState(false)
  const [titleError, setTitleError] = useState('')
  const [aiSuggestingQuestions, setAiSuggestingQuestions] = useState(false)
  const [questionBank, setQuestionBank] = useState<ScreeningQuestion[]>([])
  const [showQuestionBank, setShowQuestionBank] = useState(false)
  const [bankLoading, setBankLoading] = useState(false)

  // AI feature states
  const [aiGenerating, setAiGenerating] = useState(false)
  const [aiSuggestingSkills, setAiSuggestingSkills] = useState(false)
  const [aiSuggestingTitles, setAiSuggestingTitles] = useState(false)
  const [titleSuggestions, setTitleSuggestions] = useState<TitleSuggestion[]>([])
  const [showTitleSuggestions, setShowTitleSuggestions] = useState(false)
  const [skillSuggestions, setSkillSuggestions] = useState<SkillSuggestion[]>([])
  const [suggestedRequirements, setSuggestedRequirements] = useState<string[]>([])
  const [showSkillPanel, setShowSkillPanel] = useState(false)
  const [aiSuccess, setAiSuccess] = useState<string | null>(null)

  // Multi-country fields
  const [countryCode, setCountryCode] = useState('US')
  const [currencyCode, setCurrencyCode] = useState('USD')
  const [currencySymbol, setCurrencySymbol] = useState('$')
  const [salaryMin, setSalaryMin] = useState('')
  const [salaryMax, setSalaryMax] = useState('')
  const [countries, setCountries] = useState<{ country_code: string; country_name: string; currency_code: string; currency_symbol: string }[]>([])

  useEffect(() => {
    loadCountries()
    if (isEdit) loadJob()
  }, [id])

  async function loadCountries() {
    try {
      const data = await apiCall<{ countries: any[] }>('/countries')
      setCountries(data.countries)
    } catch { /* fallback to US only */ }
  }

  function handleCountryChange(code: string) {
    setCountryCode(code)
    const country = countries.find(c => c.country_code === code)
    if (country) {
      setCurrencyCode(country.currency_code)
      setCurrencySymbol(country.currency_symbol)
    }
  }

  async function loadJob() {
    try {
      const data = await apiCall<{ job: { title: string; company: string; description: string; requirements: string; location: string; salary_range: string; job_type: string; screening_questions: string | ScreeningQuestion[] } }>(`/jobs/${id}`)
      const job = data.job
      setTitle(job.title || '')
      setCompany(job.company || '')
      setDescription(job.description || '')
      setRequirements(job.requirements || '')
      setLocation(job.location || '')
      setSalaryRange(job.salary_range || '')
      setJobType(job.job_type || 'full-time')
      if (job.screening_questions) {
        const parsed = typeof job.screening_questions === 'string'
          ? JSON.parse(job.screening_questions)
          : job.screening_questions
        if (Array.isArray(parsed)) {
          setScreeningQuestions(parsed.map((q: ScreeningQuestion) => ({
            ...q,
            type: q.type || 'text',
            required: q.required ?? false,
          })))
        }
      }
    } catch {
      navigate('/recruiter/jobs')
    } finally {
      setLoading(false)
    }
  }

  function flashSuccess(msg: string) {
    setAiSuccess(msg)
    setTimeout(() => setAiSuccess(null), 3000)
  }

  async function handleAiGenerate() {
    if (!title.trim()) {
      setTitleError('Enter a job title first so AI can generate a description')
      return
    }
    setAiGenerating(true)
    try {
      const data = await apiCall<{ generated: { description: string; requirements: string; suggested_skills: string[]; suggested_title: string } }>('/recruiter/jobs/generate', {
        method: 'POST',
        body: { title, brief_notes: description, location, job_type: jobType },
      })
      if (data.generated) {
        setDescription(data.generated.description || '')
        setRequirements(data.generated.requirements || '')
        flashSuccess('Description & requirements generated!')
      }
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'AI generation failed')
    } finally {
      setAiGenerating(false)
    }
  }

  async function handleSuggestSkills() {
    if (!title.trim()) {
      setTitleError('Enter a job title first')
      return
    }
    setAiSuggestingSkills(true)
    try {
      const data = await apiCall<{ suggestions: { required_skills: SkillSuggestion[]; suggested_requirements: string[] } }>('/recruiter/jobs/suggest-skills', {
        method: 'POST',
        body: { title, description, current_skills: [] },
      })
      if (data.suggestions) {
        setSkillSuggestions(data.suggestions.required_skills || [])
        setSuggestedRequirements(data.suggestions.suggested_requirements || [])
        setShowSkillPanel(true)
      }
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Skill suggestion failed')
    } finally {
      setAiSuggestingSkills(false)
    }
  }

  async function handleSuggestTitles() {
    if (!title.trim()) {
      setTitleError('Enter a job title first')
      return
    }
    setAiSuggestingTitles(true)
    try {
      const data = await apiCall<{ suggestions: { suggestions: TitleSuggestion[] } }>('/recruiter/jobs/suggest-title', {
        method: 'POST',
        body: { title, description },
      })
      if (data.suggestions?.suggestions) {
        setTitleSuggestions(data.suggestions.suggestions)
        setShowTitleSuggestions(true)
      }
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Title suggestion failed')
    } finally {
      setAiSuggestingTitles(false)
    }
  }

  function applySkillsToRequirements() {
    const newReqs = suggestedRequirements.join('\n• ')
    const skillsList = skillSuggestions.map(s => s.skill).join(', ')
    const combined = `${requirements ? requirements + '\n\n' : ''}Skills: ${skillsList}\n\n• ${newReqs}`
    setRequirements(combined)
    setShowSkillPanel(false)
    flashSuccess('Skills added to requirements!')
  }

  async function handleSave() {
    if (!title.trim()) {
      setTitleError('Job title is required')
      return
    }
    setTitleError('')
    setSaving(true)
    try {
      const payload = {
        title,
        company: company || undefined,
        description,
        requirements,
        location,
        salary_range: salaryRange,
        job_type: jobType,
        screening_questions: screeningQuestions.filter(q => q.question.trim()),
        country_code: countryCode,
        currency_code: currencyCode,
        salary_min: salaryMin ? parseFloat(salaryMin) : undefined,
        salary_max: salaryMax ? parseFloat(salaryMax) : undefined,
      }
      if (isEdit) {
        await apiCall(`/recruiter/jobs/${id}`, {
          method: 'PUT',
          body: { ...payload, screening_questions: JSON.stringify(payload.screening_questions) },
        })
      } else {
        await apiCall('/recruiter/jobs', {
          method: 'POST',
          body: payload,
        })
      }
      navigate('/recruiter/jobs')
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Failed to save job')
    } finally {
      setSaving(false)
    }
  }

  async function handleAiSuggestQuestions() {
    if (!title.trim()) {
      setTitleError('Enter a job title first')
      return
    }
    setAiSuggestingQuestions(true)
    try {
      const data = await apiCall<{ success: boolean; suggestions: Array<{ question: string; type: string; category: string; options?: string[] }> }>('/recruiter/ai/suggest-questions', {
        method: 'POST',
        body: { job_title: title, job_description: description, existing_questions: screeningQuestions.map(q => q.question) },
      })
      if (data.suggestions && data.suggestions.length > 0) {
        const newQuestions = data.suggestions.map(s => ({
          id: `sq_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
          question: s.question,
          type: (s.type === 'yes_no' || s.type === 'select' ? s.type : 'text') as ScreeningQuestion['type'],
          required: false,
          options: s.options || [],
          category: s.category || 'general',
        }))
        setScreeningQuestions(prev => [...prev, ...newQuestions])
        flashSuccess(`${newQuestions.length} AI-suggested questions added!`)
      }
    } catch {
      alert('AI question suggestion failed')
    } finally {
      setAiSuggestingQuestions(false)
    }
  }

  async function loadQuestionBank() {
    setBankLoading(true)
    try {
      const data = await apiCall<{ success: boolean; questions: Array<{ id: number; question_text: string; question_type: string; category: string; options: string[] }> }>('/recruiter/question-bank')
      if (data.questions) {
        setQuestionBank(data.questions.map(q => ({
          id: `bank_${q.id}`,
          question: q.question_text,
          type: (q.question_type === 'yes_no' || q.question_type === 'select' ? q.question_type : 'text') as ScreeningQuestion['type'],
          required: false,
          options: q.options || [],
          category: q.category || 'general',
        })))
      }
      setShowQuestionBank(true)
    } catch {
      alert('Failed to load question bank')
    } finally {
      setBankLoading(false)
    }
  }

  async function saveQuestionsToBank() {
    const toSave = screeningQuestions.filter(q => q.question.trim())
    if (toSave.length === 0) return
    try {
      for (const q of toSave) {
        await apiCall('/recruiter/question-bank', {
          method: 'POST',
          body: { question_text: q.question, question_type: q.type, category: q.category || 'general', options: q.options || [] },
        })
      }
      flashSuccess(`${toSave.length} questions saved to your bank!`)
    } catch {
      alert('Failed to save to question bank')
    }
  }

  function addQuestion(template?: ScreeningQuestion) {
    const newQ: ScreeningQuestion = template
      ? { ...template, id: `sq_${Date.now()}_${Math.random().toString(36).slice(2, 6)}` }
      : { question: '', type: 'text', required: false, id: `sq_${Date.now()}_${Math.random().toString(36).slice(2, 6)}` }
    setScreeningQuestions(prev => [...prev, newQ])
    setShowTemplates(false)
  }

  function addAllDefaults() {
    const existing = new Set(screeningQuestions.map(q => q.question.toLowerCase()))
    const toAdd = defaultQuestionTemplates
      .filter(t => !existing.has(t.question.toLowerCase()))
      .map(t => ({ ...t, id: `sq_${Date.now()}_${Math.random().toString(36).slice(2, 6)}` }))
    setScreeningQuestions(prev => [...prev, ...toAdd])
    setShowTemplates(false)
  }

  function updateQuestion(index: number, updates: Partial<ScreeningQuestion>) {
    setScreeningQuestions(prev => prev.map((q, i) => i === index ? { ...q, ...updates } : q))
  }

  function removeQuestion(index: number) {
    setScreeningQuestions(prev => prev.filter((_, i) => i !== index))
  }

  function addOption(qIndex: number) {
    setScreeningQuestions(prev => prev.map((q, i) =>
      i === qIndex ? { ...q, options: [...(q.options || []), ''] } : q
    ))
  }

  function updateOption(qIndex: number, optIndex: number, value: string) {
    setScreeningQuestions(prev => prev.map((q, i) =>
      i === qIndex ? { ...q, options: (q.options || []).map((o, j) => j === optIndex ? value : o) } : q
    ))
  }

  function removeOption(qIndex: number, optIndex: number) {
    setScreeningQuestions(prev => prev.map((q, i) =>
      i === qIndex ? { ...q, options: (q.options || []).filter((_, j) => j !== optIndex) } : q
    ))
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center py-16">
        <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
      </div>
    )
  }

  return (
    <div className="max-w-2xl space-y-6">
      {/* AI Success Toast */}
      {aiSuccess && (
        <div className="fixed top-4 right-4 z-50 animate-in fade-in slide-in-from-top-2 bg-green-600 text-white px-4 py-2 rounded-lg shadow-lg flex items-center gap-2 text-sm">
          <CheckCircle2 className="h-4 w-4" />
          {aiSuccess}
        </div>
      )}

      <div className="flex items-center gap-3">
        <Button variant="ghost" size="sm" onClick={() => navigate('/recruiter/jobs')}>
          <ArrowLeft className="h-4 w-4" />
        </Button>
        <div>
          <h1 className="font-heading text-2xl font-bold">
            {isEdit ? 'Edit Job' : 'Post New Job'}
          </h1>
          <p className="text-muted-foreground text-sm">
            {isEdit ? 'Update your job listing' : 'Create a new job posting'}
          </p>
        </div>
      </div>

      {/* Job details */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Briefcase className="h-5 w-5" /> Job Details
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div>
            <div className="flex items-center justify-between">
              <Label>Job Title *</Label>
              <Button
                variant="ghost"
                size="sm"
                onClick={handleSuggestTitles}
                disabled={aiSuggestingTitles || !title.trim()}
                className="h-7 text-xs gap-1 text-primary hover:text-primary"
              >
                {aiSuggestingTitles ? <Loader2 className="h-3 w-3 animate-spin" /> : <Lightbulb className="h-3 w-3" />}
                Suggest Titles
              </Button>
            </div>
            <Input
              value={title}
              onChange={e => { setTitle(e.target.value); setTitleError('') }}
              placeholder="e.g. Senior Software Engineer"
              className={`mt-1 ${titleError ? 'border-destructive' : ''}`}
            />
            {titleError && (
              <p className="text-xs text-destructive mt-1 flex items-center gap-1">
                <AlertCircle className="h-3 w-3" />{titleError}
              </p>
            )}
            {/* AI Title Suggestions */}
            {showTitleSuggestions && titleSuggestions.length > 0 && (
              <div className="mt-2 rounded-lg border bg-blue-50/50 p-3 space-y-2">
                <div className="flex items-center justify-between">
                  <p className="text-xs font-medium text-blue-700 flex items-center gap-1">
                    <Sparkles className="h-3 w-3" /> AI Title Suggestions
                  </p>
                  <Button variant="ghost" size="sm" onClick={() => setShowTitleSuggestions(false)} className="h-6 w-6 p-0">
                    <X className="h-3 w-3" />
                  </Button>
                </div>
                {titleSuggestions.map((s, i) => (
                  <button
                    key={i}
                    onClick={() => { setTitle(s.title); setShowTitleSuggestions(false); flashSuccess('Title updated!') }}
                    className="w-full text-left rounded-md border bg-white p-2.5 text-sm hover:border-primary/40 hover:bg-blue-50 transition-colors cursor-pointer"
                  >
                    <div className="flex items-center justify-between">
                      <span className="font-medium">{s.title}</span>
                      {s.search_volume && (
                        <Badge variant="outline" className="text-[9px]">{s.search_volume} search</Badge>
                      )}
                    </div>
                    <p className="text-xs text-muted-foreground mt-0.5">{s.reason}</p>
                  </button>
                ))}
              </div>
            )}
          </div>

          <div>
            <Label>Company Name <span className="text-muted-foreground text-xs">(auto-filled from your account if blank)</span></Label>
            <Input
              value={company}
              onChange={e => setCompany(e.target.value)}
              placeholder="Leave blank to use your company name"
              className="mt-1"
            />
          </div>

          <div className="grid grid-cols-1 gap-4 sm:grid-cols-3">
            <div>
              <Label>Job Type</Label>
              <Select value={jobType} onChange={e => setJobType(e.target.value)} className="mt-1">
                <option value="full-time">Full-time</option>
                <option value="part-time">Part-time</option>
                <option value="contract">Contract</option>
                <option value="internship">Internship</option>
                <option value="remote">Remote</option>
                <option value="freelance">Freelance</option>
              </Select>
            </div>
            <div>
              <Label>Country</Label>
              <Select value={countryCode} onChange={e => handleCountryChange(e.target.value)} className="mt-1">
                {countries.length > 0 ? countries.map(c => (
                  <option key={c.country_code} value={c.country_code}>{c.country_name}</option>
                )) : (
                  <>
                    <option value="US">United States</option>
                    <option value="IN">India</option>
                    <option value="GB">United Kingdom</option>
                    <option value="CA">Canada</option>
                    <option value="DE">Germany</option>
                    <option value="FR">France</option>
                    <option value="AU">Australia</option>
                    <option value="SG">Singapore</option>
                  </>
                )}
              </Select>
            </div>
            <div>
              <Label>Location</Label>
              <Input
                value={location}
                onChange={e => setLocation(e.target.value)}
                placeholder="e.g. New York, NY or Remote"
                className="mt-1"
              />
            </div>
          </div>

          <div className="grid grid-cols-1 gap-4 sm:grid-cols-3">
            <div>
              <Label>Min Salary ({currencySymbol})</Label>
              <Input
                type="number"
                value={salaryMin}
                onChange={e => setSalaryMin(e.target.value)}
                placeholder={`e.g. ${currencyCode === 'INR' ? '800000' : currencyCode === 'GBP' ? '40000' : '80000'}`}
                className="mt-1"
              />
            </div>
            <div>
              <Label>Max Salary ({currencySymbol})</Label>
              <Input
                type="number"
                value={salaryMax}
                onChange={e => setSalaryMax(e.target.value)}
                placeholder={`e.g. ${currencyCode === 'INR' ? '1500000' : currencyCode === 'GBP' ? '70000' : '120000'}`}
                className="mt-1"
              />
            </div>
            <div>
              <Label>Salary Range (text) <span className="text-muted-foreground text-xs">(optional override)</span></Label>
              <Input
                value={salaryRange}
                onChange={e => setSalaryRange(e.target.value)}
                placeholder={`e.g. ${currencySymbol}80,000 - ${currencySymbol}120,000`}
                className="mt-1"
              />
            </div>
          </div>
          {currencyCode !== 'USD' && (
            <div className="flex items-center gap-2">
              <Badge variant="outline" className="text-xs">
                {currencyCode} ({currencySymbol})
              </Badge>
              <span className="text-xs text-muted-foreground">Salary will be displayed in {currencyCode}</span>
            </div>
          )}

          <div>
            <div className="flex items-center justify-between">
              <Label>Job Description</Label>
              <Button
                variant="outline"
                size="sm"
                onClick={handleAiGenerate}
                disabled={aiGenerating || !title.trim()}
                className="h-7 text-xs gap-1.5 border-primary/30 text-primary hover:bg-primary hover:text-white transition-colors"
              >
                {aiGenerating ? <Loader2 className="h-3 w-3 animate-spin" /> : <Wand2 className="h-3 w-3" />}
                {aiGenerating ? 'Generating...' : '✨ Generate with AI'}
              </Button>
            </div>
            <Textarea
              value={description}
              onChange={e => setDescription(e.target.value)}
              placeholder="Describe the role, responsibilities, and what a typical day looks like... or click 'Generate with AI' to auto-fill"
              rows={6}
              className="mt-1"
            />
            {aiGenerating && (
              <div className="mt-2 flex items-center gap-2 text-xs text-primary">
                <Loader2 className="h-3 w-3 animate-spin" />
                AI is writing a tailored description based on your job title...
              </div>
            )}
          </div>

          <div>
            <div className="flex items-center justify-between">
              <Label>Requirements</Label>
              <Button
                variant="ghost"
                size="sm"
                onClick={handleSuggestSkills}
                disabled={aiSuggestingSkills || !title.trim()}
                className="h-7 text-xs gap-1 text-primary hover:text-primary"
              >
                {aiSuggestingSkills ? <Loader2 className="h-3 w-3 animate-spin" /> : <Lightbulb className="h-3 w-3" />}
                Suggest Skills
              </Button>
            </div>
            <Textarea
              value={requirements}
              onChange={e => setRequirements(e.target.value)}
              placeholder="List the required skills, experience, and qualifications..."
              rows={4}
              className="mt-1"
            />
            {/* AI Skills Panel */}
            {showSkillPanel && (skillSuggestions.length > 0 || suggestedRequirements.length > 0) && (
              <div className="mt-2 rounded-lg border bg-violet-50/50 p-3 space-y-3">
                <div className="flex items-center justify-between">
                  <p className="text-xs font-medium text-violet-700 flex items-center gap-1">
                    <Sparkles className="h-3 w-3" /> AI Suggested Skills & Requirements
                  </p>
                  <Button variant="ghost" size="sm" onClick={() => setShowSkillPanel(false)} className="h-6 w-6 p-0">
                    <X className="h-3 w-3" />
                  </Button>
                </div>
                {skillSuggestions.length > 0 && (
                  <div className="flex flex-wrap gap-1.5">
                    {skillSuggestions.map((s, i) => (
                      <span
                        key={i}
                        className={`text-[11px] rounded-full px-2.5 py-1 border ${
                          s.importance === 'must-have'
                            ? 'bg-violet-100 text-violet-700 border-violet-200 font-medium'
                            : 'bg-white text-muted-foreground border-gray-200'
                        }`}
                      >
                        {s.skill}
                        {s.importance === 'must-have' && <span className="ml-1 text-[9px]">★</span>}
                      </span>
                    ))}
                  </div>
                )}
                {suggestedRequirements.length > 0 && (
                  <div className="text-xs text-muted-foreground space-y-1">
                    {suggestedRequirements.slice(0, 5).map((r, i) => (
                      <p key={i} className="flex items-start gap-1.5">
                        <CheckCircle2 className="h-3 w-3 text-violet-400 mt-0.5 shrink-0" />
                        {r}
                      </p>
                    ))}
                  </div>
                )}
                <Button
                  size="sm"
                  onClick={applySkillsToRequirements}
                  className="w-full text-xs gap-1 bg-violet-600 hover:bg-violet-700"
                >
                  <Plus className="h-3 w-3" /> Apply to Requirements
                </Button>
              </div>
            )}
          </div>
        </CardContent>
      </Card>

      {/* Screening Questions */}
      <Card>
        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-4">
          <CardTitle className="flex items-center gap-2">
            <ListChecks className="h-5 w-5" /> Pre-screening Questions
          </CardTitle>
          <div className="flex items-center gap-2 flex-wrap">
            <Button
              variant="outline"
              size="sm"
              onClick={handleAiSuggestQuestions}
              disabled={aiSuggestingQuestions || !title.trim()}
              className="gap-1 border-primary/30 text-primary hover:bg-primary hover:text-white"
            >
              {aiSuggestingQuestions ? <Loader2 className="h-3 w-3 animate-spin" /> : <Wand2 className="h-3 w-3" />}
              AI Suggest
            </Button>
            <Button variant="outline" size="sm" onClick={loadQuestionBank} disabled={bankLoading} className="gap-1">
              {bankLoading ? <Loader2 className="h-3 w-3 animate-spin" /> : <Lightbulb className="h-3 w-3" />}
              My Bank
            </Button>
            <Button variant="outline" size="sm" onClick={() => setShowTemplates(!showTemplates)} className="gap-1">
              <Sparkles className="h-3 w-3" /> Templates
            </Button>
            <Button variant="outline" size="sm" onClick={() => addQuestion()} className="gap-1">
              <Plus className="h-3 w-3" /> Custom
            </Button>
          </div>
        </CardHeader>
        <CardContent>
          {/* Templates dropdown */}
          {showTemplates && (
            <div className="mb-4 rounded-lg border bg-muted/30 p-3 space-y-2">
              <div className="flex items-center justify-between mb-2">
                <p className="text-sm font-medium">Common Questions</p>
                <Button variant="ghost" size="sm" onClick={addAllDefaults} className="text-xs">
                  Add All
                </Button>
              </div>
              {defaultQuestionTemplates.map((t, i) => {
                const alreadyAdded = screeningQuestions.some(q => q.question.toLowerCase() === t.question.toLowerCase())
                return (
                  <button
                    key={i}
                    onClick={() => !alreadyAdded && addQuestion(t)}
                    disabled={alreadyAdded}
                    className={`w-full text-left rounded-md border p-2.5 text-sm transition-colors ${
                      alreadyAdded
                        ? 'opacity-50 cursor-not-allowed bg-muted'
                        : 'hover:bg-background hover:border-primary/30 cursor-pointer'
                    }`}
                  >
                    <div className="flex items-center justify-between">
                      <span>{t.question}</span>
                      <div className="flex items-center gap-1.5">
                        <Badge variant="outline" className="text-[10px]">{typeLabels[t.type]}</Badge>
                        {t.required && <Badge variant="secondary" className="text-[10px]">Required</Badge>}
                        {alreadyAdded && <span className="text-[10px] text-muted-foreground">Added</span>}
                      </div>
                    </div>
                  </button>
                )
              })}
            </div>
          )}

          {/* Question Bank panel */}
          {showQuestionBank && (
            <div className="mb-4 rounded-lg border bg-indigo-50/30 p-3 space-y-2">
              <div className="flex items-center justify-between mb-2">
                <p className="text-sm font-medium flex items-center gap-1">
                  <Lightbulb className="h-3.5 w-3.5 text-indigo-600" /> Your Question Bank
                </p>
                <Button variant="ghost" size="sm" onClick={() => setShowQuestionBank(false)} className="h-6 w-6 p-0">
                  <X className="h-3 w-3" />
                </Button>
              </div>
              {questionBank.length === 0 ? (
                <p className="text-xs text-muted-foreground text-center py-4">No saved questions yet. Add screening questions and save them to your bank.</p>
              ) : (
                questionBank.map((q, i) => {
                  const alreadyAdded = screeningQuestions.some(sq => sq.question.toLowerCase() === q.question.toLowerCase())
                  return (
                    <button
                      key={q.id || i}
                      onClick={() => {
                        if (!alreadyAdded) {
                          addQuestion({ ...q, id: `sq_${Date.now()}_${Math.random().toString(36).slice(2, 6)}` })
                        }
                      }}
                      disabled={alreadyAdded}
                      className={`w-full text-left rounded-md border p-2.5 text-sm transition-colors ${
                        alreadyAdded ? 'opacity-50 cursor-not-allowed bg-muted' : 'hover:bg-white hover:border-indigo-300 cursor-pointer'
                      }`}
                    >
                      <div className="flex items-center justify-between">
                        <span>{q.question}</span>
                        <div className="flex items-center gap-1.5">
                          {q.category && <Badge variant="outline" className="text-[10px]">{q.category}</Badge>}
                          {alreadyAdded && <span className="text-[10px] text-muted-foreground">Added</span>}
                        </div>
                      </div>
                    </button>
                  )
                })
              )}
            </div>
          )}

          {screeningQuestions.length === 0 ? (
            <div className="text-center py-8">
              <ListChecks className="mx-auto mb-2 h-8 w-8 opacity-30" />
              <p className="text-sm text-muted-foreground mb-1">No screening questions</p>
              <p className="text-xs text-muted-foreground">Add questions to filter candidates before reviewing applications</p>
            </div>
          ) : (
            <div className="space-y-3">
              {screeningQuestions.map((q, i) => (
                <div key={q.id || i} className="rounded-lg border p-4 space-y-3 group">
                  <div className="flex items-start gap-2">
                    <GripVertical className="h-4 w-4 mt-2.5 text-muted-foreground/40 shrink-0" />
                    <div className="flex-1 space-y-3">
                      {/* Question text */}
                      <Input
                        value={q.question}
                        onChange={e => updateQuestion(i, { question: e.target.value })}
                        placeholder={`Question ${i + 1}...`}
                      />

                      {/* Type and options row */}
                      <div className="flex flex-wrap items-center gap-2">
                        <Select
                          value={q.type}
                          onChange={e => {
                            const newType = e.target.value as ScreeningQuestion['type']
                            const updates: Partial<ScreeningQuestion> = { type: newType }
                            if (newType === 'select' && (!q.options || q.options.length === 0)) {
                              updates.options = ['']
                            }
                            if (newType !== 'select') {
                              updates.options = undefined
                            }
                            updateQuestion(i, updates)
                          }}
                          className="w-32 text-xs"
                        >
                          <option value="text">Text</option>
                          <option value="yes_no">Yes / No</option>
                          <option value="select">Dropdown</option>
                        </Select>

                        <label className="flex items-center gap-1.5 text-xs text-muted-foreground cursor-pointer">
                          <input
                            type="checkbox"
                            checked={q.required}
                            onChange={() => updateQuestion(i, { required: !q.required })}
                            className="rounded"
                          />
                          Required
                        </label>

                        {q.type === 'text' && (
                          <Input
                            value={q.placeholder || ''}
                            onChange={e => updateQuestion(i, { placeholder: e.target.value })}
                            placeholder="Placeholder text..."
                            className="flex-1 text-xs h-8"
                          />
                        )}
                      </div>

                      {/* Options for select type */}
                      {q.type === 'select' && (
                        <div className="space-y-2 pl-2 border-l-2 border-muted">
                          <p className="text-xs text-muted-foreground font-medium">Dropdown Options</p>
                          {(q.options || []).map((opt, oi) => (
                            <div key={oi} className="flex items-center gap-2">
                              <span className="text-xs text-muted-foreground w-4">{oi + 1}.</span>
                              <Input
                                value={opt}
                                onChange={e => updateOption(i, oi, e.target.value)}
                                placeholder={`Option ${oi + 1}`}
                                className="flex-1 text-sm h-8"
                              />
                              <Button
                                variant="ghost"
                                size="icon"
                                className="h-8 w-8 shrink-0"
                                onClick={() => removeOption(i, oi)}
                              >
                                <X className="h-3 w-3" />
                              </Button>
                            </div>
                          ))}
                          <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => addOption(i)}
                            className="text-xs gap-1"
                          >
                            <Plus className="h-3 w-3" /> Add Option
                          </Button>
                        </div>
                      )}
                    </div>

                    <Button
                      variant="ghost"
                      size="icon"
                      onClick={() => removeQuestion(i)}
                      className="shrink-0 text-muted-foreground hover:text-destructive"
                    >
                      <X className="h-4 w-4" />
                    </Button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Save questions to bank */}
      {screeningQuestions.length > 0 && (
        <div className="flex justify-end">
          <Button variant="ghost" size="sm" onClick={saveQuestionsToBank} className="gap-1 text-xs text-muted-foreground">
            <Save className="h-3 w-3" /> Save Questions to My Bank
          </Button>
        </div>
      )}

      {/* Actions */}
      <div className="flex gap-2 sticky bottom-4 bg-background/80 backdrop-blur-sm py-3 rounded-lg">
        <Button onClick={handleSave} disabled={saving} className="gap-2">
          {saving ? (
            <div className="h-4 w-4 animate-spin rounded-full border-2 border-white border-t-transparent" />
          ) : (
            <Save className="h-4 w-4" />
          )}
          {isEdit ? 'Update Job' : 'Publish Job'}
        </Button>
        <Button variant="outline" onClick={() => navigate('/recruiter/jobs')}>Cancel</Button>
      </div>
    </div>
  )
}

import { useEffect, useState } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { apiCall } from '@/lib/api'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Select } from '@/components/ui/select'
import { Textarea } from '@/components/ui/textarea'
import { Input } from '@/components/ui/input'
import { Dialog, DialogHeader, DialogTitle } from '@/components/ui/dialog'
import {
  ArrowLeft, Users, Star, Calendar, Search, LayoutGrid, List,
  Mail, FileText, Send, CheckCircle, Clock, Gift, MessageSquare,
  ChevronRight, Zap, Target, AlertCircle, Sparkles, Loader2, X,
} from 'lucide-react'

interface JobInfo {
  id: number
  title: string
  screening_questions?: string | ScreeningQuestion[]
}

interface ScreeningQuestion {
  id?: string
  question: string
  type?: string
  required?: boolean
  category?: string
}

interface Applicant {
  id: number
  candidate_id: number
  job_id: number
  status: string
  candidate_name: string
  candidate_email: string
  applied_at: string
  updated_at: string
  match_score?: number
  omniscore_at_apply?: number
  current_omniscore?: number
  score_tier?: string
  cover_letter?: string
  screening_answers?: string
  recruiter_notes?: string
  matching_skills?: string[] | string
  missing_skills?: string[] | string
  similarity_score?: number
  match_explanation?: string | Record<string, string>
}

// Aligned with backend PIPELINE_STAGES
const statuses = ['applied', 'screening', 'shortlisted', 'reviewing', 'interviewed', 'offered', 'hired', 'rejected', 'withdrawn']
const kanbanStages = ['applied', 'screening', 'shortlisted', 'reviewing', 'interviewed', 'offered', 'hired']

const statusConfig: Record<string, { label: string; variant: 'default' | 'secondary' | 'success' | 'warning' | 'destructive'; color: string }> = {
  applied: { label: 'New', variant: 'secondary', color: 'border-blue-300 bg-blue-50' },
  screening: { label: 'Screening', variant: 'default', color: 'border-purple-300 bg-purple-50' },
  shortlisted: { label: 'Shortlisted', variant: 'default', color: 'border-indigo-300 bg-indigo-50' },
  reviewing: { label: 'Reviewing', variant: 'warning', color: 'border-amber-300 bg-amber-50' },
  interviewed: { label: 'Interviewed', variant: 'default', color: 'border-cyan-300 bg-cyan-50' },
  offered: { label: 'Offered', variant: 'success', color: 'border-emerald-300 bg-emerald-50' },
  hired: { label: 'Hired', variant: 'success', color: 'border-green-300 bg-green-50' },
  rejected: { label: 'Rejected', variant: 'destructive', color: 'border-red-300 bg-red-50' },
  withdrawn: { label: 'Withdrawn', variant: 'secondary', color: 'border-gray-300 bg-gray-50' },
}

function matchScoreColor(score: number): string {
  if (score >= 80) return 'text-green-600'
  if (score >= 60) return 'text-amber-600'
  return 'text-red-500'
}

function matchScoreBg(score: number): string {
  if (score >= 80) return 'bg-green-100 text-green-700 border-green-200'
  if (score >= 60) return 'bg-amber-100 text-amber-700 border-amber-200'
  return 'bg-red-100 text-red-700 border-red-200'
}

export function RecruiterJobApplicantsPage() {
  const { id } = useParams()
  const navigate = useNavigate()
  const [job, setJob] = useState<JobInfo | null>(null)
  const [applicants, setApplicants] = useState<Applicant[]>([])
  const [loading, setLoading] = useState(true)
  const [statusFilter, setStatusFilter] = useState('')
  const [searchQuery, setSearchQuery] = useState('')
  const [selected, setSelected] = useState<Applicant | null>(null)
  const [notes, setNotes] = useState('')
  const [updating, setUpdating] = useState(false)
  const [viewMode, setViewMode] = useState<'list' | 'kanban'>('kanban')
  const [selectedIds, setSelectedIds] = useState<Set<number>>(new Set())
  const [batchUpdating, setBatchUpdating] = useState(false)
  const [aiSummary, setAiSummary] = useState<string | null>(null)
  const [aiSummaryLoading, setAiSummaryLoading] = useState(false)

  useEffect(() => {
    loadApplicants()
  }, [id])

  async function loadApplicants() {
    try {
      const data = await apiCall<{ job: JobInfo; applications: Applicant[] }>(
        `/recruiter/jobs/${id}/applications`
      )
      setJob(data.job)
      setApplicants(data.applications || [])
    } catch {
      navigate('/recruiter/jobs')
    } finally {
      setLoading(false)
    }
  }

  async function updateStatus(appId: number, newStatus: string) {
    setUpdating(true)
    try {
      await apiCall(`/recruiter/applications/${appId}`, {
        method: 'PUT',
        body: { status: newStatus, recruiter_notes: notes || undefined },
      })
      setApplicants(prev => prev.map(a => a.id === appId ? { ...a, status: newStatus } : a))
      if (selected?.id === appId) {
        setSelected(prev => prev ? { ...prev, status: newStatus } : null)
      }
    } catch {
      // silent
    } finally {
      setUpdating(false)
    }
  }

  async function batchUpdateStatus(newStatus: string) {
    if (selectedIds.size === 0) return
    setBatchUpdating(true)
    try {
      await apiCall('/recruiter/applications/batch-status', {
        method: 'PUT',
        body: { application_ids: Array.from(selectedIds), status: newStatus },
      })
      setApplicants(prev => prev.map(a => selectedIds.has(a.id) ? { ...a, status: newStatus } : a))
      setSelectedIds(new Set())
    } catch {
      // silent
    } finally {
      setBatchUpdating(false)
    }
  }

  async function generateAiSummary(applicationId: number) {
    setAiSummaryLoading(true)
    setAiSummary(null)
    try {
      const data = await apiCall<{ success: boolean; summary: { overall_assessment: string; strengths: string[]; concerns: string[]; recommendation: string; fit_score: number } }>('/recruiter/ai/candidate-summary', {
        method: 'POST',
        body: { application_id: applicationId },
      })
      if (data.summary) {
        const parts: string[] = []
        parts.push(`**Assessment:** ${data.summary.overall_assessment}`)
        if (data.summary.fit_score) parts.push(`**Fit Score:** ${data.summary.fit_score}/100`)
        if (data.summary.strengths?.length) parts.push(`**Strengths:** ${data.summary.strengths.join(', ')}`)
        if (data.summary.concerns?.length) parts.push(`**Concerns:** ${data.summary.concerns.join(', ')}`)
        if (data.summary.recommendation) parts.push(`**Recommendation:** ${data.summary.recommendation}`)
        setAiSummary(parts.join('\n\n'))
      }
    } catch {
      setAiSummary('AI summary could not be generated. The candidate may not have enough profile data.')
    } finally {
      setAiSummaryLoading(false)
    }
  }

  function toggleSelect(appId: number) {
    setSelectedIds(prev => {
      const next = new Set(prev)
      if (next.has(appId)) next.delete(appId)
      else next.add(appId)
      return next
    })
  }

  // Parse screening questions
  const jobScreeningQuestions: ScreeningQuestion[] = (() => {
    if (!job?.screening_questions) return []
    try {
      const raw = typeof job.screening_questions === 'string'
        ? JSON.parse(job.screening_questions) : job.screening_questions
      return Array.isArray(raw) ? raw : []
    } catch { return [] }
  })()

  function getQuestionLabel(key: string, index: number): string {
    const byId = jobScreeningQuestions.find(q => q.id === key)
    if (byId) return byId.question
    const match = key.match(/^q(\d+)$/)
    if (match) {
      const qIndex = parseInt(match[1])
      if (jobScreeningQuestions[qIndex]) return jobScreeningQuestions[qIndex].question
    }
    return `Question ${index + 1}`
  }

  function parseSkills(raw?: string[] | string): string[] {
    if (!raw) return []
    if (Array.isArray(raw)) return raw
    try { return JSON.parse(raw) } catch { return [] }
  }

  const filtered = applicants.filter(a => {
    const matchStatus = !statusFilter || a.status === statusFilter
    const matchSearch = !searchQuery ||
      a.candidate_name?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      a.candidate_email?.toLowerCase().includes(searchQuery.toLowerCase())
    return matchStatus && matchSearch
  })

  const statusCounts = statuses.reduce((acc, s) => {
    acc[s] = applicants.filter(a => a.status === s).length
    return acc
  }, {} as Record<string, number>)

  function timeAgo(dateStr: string) {
    const diff = Date.now() - new Date(dateStr).getTime()
    const days = Math.floor(diff / 86400000)
    if (days === 0) return 'Today'
    if (days === 1) return '1d ago'
    if (days < 30) return `${days}d ago`
    return `${Math.floor(days / 30)}mo ago`
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center py-16">
        <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
      </div>
    )
  }

  return (
    <div className="space-y-5">
      {/* Header */}
      <div className="flex items-center gap-3">
        <Button variant="ghost" size="sm" onClick={() => navigate('/recruiter/jobs')}>
          <ArrowLeft className="h-4 w-4" />
        </Button>
        <div className="flex-1">
          <h1 className="font-heading text-2xl font-bold">Pipeline</h1>
          <p className="text-muted-foreground text-sm">
            {job?.title || 'Job'} &mdash; {applicants.length} applicant{applicants.length !== 1 ? 's' : ''}
          </p>
        </div>
        <div className="flex items-center gap-1 border rounded-lg p-0.5">
          <Button
            variant={viewMode === 'kanban' ? 'default' : 'ghost'}
            size="sm"
            onClick={() => setViewMode('kanban')}
            className="gap-1 h-7 px-2"
          >
            <LayoutGrid className="h-3.5 w-3.5" /> Board
          </Button>
          <Button
            variant={viewMode === 'list' ? 'default' : 'ghost'}
            size="sm"
            onClick={() => setViewMode('list')}
            className="gap-1 h-7 px-2"
          >
            <List className="h-3.5 w-3.5" /> List
          </Button>
        </div>
      </div>

      {/* Stats row */}
      <div className="grid gap-3 grid-cols-2 sm:grid-cols-4">
        <Card><CardContent className="p-3 text-center">
          <p className="text-2xl font-bold">{applicants.length}</p>
          <p className="text-xs text-muted-foreground">Total</p>
        </CardContent></Card>
        <Card><CardContent className="p-3 text-center">
          <p className="text-2xl font-bold text-blue-600">{statusCounts.applied || 0}</p>
          <p className="text-xs text-muted-foreground">New</p>
        </CardContent></Card>
        <Card><CardContent className="p-3 text-center">
          <p className="text-2xl font-bold text-amber-600">
            {(statusCounts.screening || 0) + (statusCounts.shortlisted || 0) + (statusCounts.reviewing || 0)}
          </p>
          <p className="text-xs text-muted-foreground">In Pipeline</p>
        </CardContent></Card>
        <Card><CardContent className="p-3 text-center">
          <p className="text-2xl font-bold text-emerald-600">
            {(statusCounts.offered || 0) + (statusCounts.hired || 0)}
          </p>
          <p className="text-xs text-muted-foreground">Offered/Hired</p>
        </CardContent></Card>
      </div>

      {/* Search + bulk actions */}
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
          <Input
            placeholder="Search by name or email..."
            value={searchQuery}
            onChange={e => setSearchQuery(e.target.value)}
            className="pl-9"
          />
        </div>
        {selectedIds.size > 0 && (
          <div className="flex items-center gap-2">
            <span className="text-sm text-muted-foreground">{selectedIds.size} selected</span>
            <Select
              value=""
              onChange={e => { if (e.target.value) batchUpdateStatus(e.target.value) }}
              className="w-36 text-xs"
              disabled={batchUpdating}
            >
              <option value="">Bulk action...</option>
              {statuses.map(s => (
                <option key={s} value={s}>Move to {statusConfig[s]?.label || s}</option>
              ))}
            </Select>
            <Button variant="ghost" size="sm" onClick={() => setSelectedIds(new Set())}>Clear</Button>
          </div>
        )}
      </div>

      {/* KANBAN VIEW */}
      {viewMode === 'kanban' ? (
        <div className="overflow-x-auto pb-4">
          <div className="flex gap-3 min-w-[900px]">
            {kanbanStages.map(stage => {
              const stageApps = applicants.filter(a => a.status === stage)
              const cfg = statusConfig[stage]
              return (
                <div key={stage} className="flex-1 min-w-[160px]">
                  <div className={`rounded-t-lg border-t-2 px-3 py-2 ${cfg.color} border-b`}>
                    <div className="flex items-center justify-between">
                      <span className="text-xs font-semibold">{cfg.label}</span>
                      <Badge variant="secondary" className="text-[10px] h-5 px-1.5">{stageApps.length}</Badge>
                    </div>
                  </div>
                  <div className="space-y-2 pt-2 min-h-[120px]">
                    {stageApps.length === 0 ? (
                      <p className="text-[10px] text-muted-foreground text-center py-6 italic">No candidates</p>
                    ) : stageApps.map(app => (
                      <div
                        key={app.id}
                        className="rounded-lg border bg-card p-2.5 cursor-pointer hover:shadow-md transition-shadow"
                        onClick={() => { setSelected(app); setNotes(app.recruiter_notes || ''); setAiSummary(null) }}
                      >
                        <div className="flex items-center gap-2 mb-1.5">
                          <div className="flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-primary/10 text-primary font-semibold text-[10px]">
                            {(app.candidate_name || '?')[0].toUpperCase()}
                          </div>
                          <span className="text-xs font-medium truncate">{app.candidate_name}</span>
                        </div>
                        <div className="flex items-center gap-2 text-[10px] text-muted-foreground">
                          {app.match_score != null && (
                            <span className={`font-bold ${matchScoreColor(app.match_score)}`}>
                              {app.match_score}%
                            </span>
                          )}
                          <span>{timeAgo(app.applied_at)}</span>
                          {app.cover_letter && <FileText className="h-2.5 w-2.5" />}
                        </div>
                        {/* Quick advance button */}
                        {stage !== 'hired' && (
                          <Button
                            variant="ghost"
                            size="sm"
                            className="w-full mt-1.5 h-6 text-[10px] gap-1 text-muted-foreground hover:text-primary"
                            onClick={e => {
                              e.stopPropagation()
                              const nextIdx = kanbanStages.indexOf(stage) + 1
                              if (nextIdx < kanbanStages.length) {
                                updateStatus(app.id, kanbanStages[nextIdx])
                              }
                            }}
                          >
                            <ChevronRight className="h-3 w-3" />
                            Advance
                          </Button>
                        )}
                      </div>
                    ))}
                  </div>
                </div>
              )
            })}
          </div>
          {/* Rejected/Withdrawn counts */}
          {((statusCounts.rejected || 0) + (statusCounts.withdrawn || 0)) > 0 && (
            <div className="flex gap-3 mt-3 text-xs text-muted-foreground">
              {statusCounts.rejected > 0 && (
                <span className="flex items-center gap-1">
                  <AlertCircle className="h-3 w-3 text-red-400" /> {statusCounts.rejected} rejected
                </span>
              )}
              {statusCounts.withdrawn > 0 && (
                <span className="flex items-center gap-1">{statusCounts.withdrawn} withdrawn</span>
              )}
            </div>
          )}
        </div>
      ) : (
        /* LIST VIEW */
        <>
          {/* Status filter pills */}
          <div className="flex flex-wrap gap-2">
            <Button variant={!statusFilter ? 'default' : 'outline'} size="sm" onClick={() => setStatusFilter('')}>
              All ({applicants.length})
            </Button>
            {statuses.map(s => (
              statusCounts[s] > 0 ? (
                <Button key={s} variant={statusFilter === s ? 'default' : 'outline'} size="sm" onClick={() => setStatusFilter(s)}>
                  {statusConfig[s]?.label || s} ({statusCounts[s]})
                </Button>
              ) : null
            ))}
          </div>

          {filtered.length === 0 ? (
            <Card>
              <CardContent className="py-16 text-center">
                <Users className="mx-auto mb-3 h-10 w-10 opacity-30" />
                <p className="text-muted-foreground">
                  {applicants.length === 0 ? 'No applicants yet' : 'No matches'}
                </p>
              </CardContent>
            </Card>
          ) : (
            <div className="space-y-2">
              {filtered.map(app => {
                const config = statusConfig[app.status] || { label: app.status, variant: 'secondary' as const, color: '' }
                return (
                  <Card
                    key={app.id}
                    className={`cursor-pointer transition-shadow hover:shadow-md ${selectedIds.has(app.id) ? 'ring-2 ring-primary' : ''}`}
                    onClick={() => { setSelected(app); setNotes(app.recruiter_notes || ''); setAiSummary(null) }}
                  >
                    <CardContent className="p-4">
                      <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
                        <div className="min-w-0 flex items-center gap-3">
                          <input
                            type="checkbox"
                            checked={selectedIds.has(app.id)}
                            onChange={e => { e.stopPropagation(); toggleSelect(app.id) }}
                            onClick={e => e.stopPropagation()}
                            className="h-4 w-4 rounded border-gray-300 shrink-0"
                          />
                          <div className="min-w-0">
                            <div className="flex items-center gap-2 mb-1">
                              <div className="flex h-7 w-7 shrink-0 items-center justify-center rounded-full bg-primary/10 text-primary font-semibold text-xs">
                                {(app.candidate_name || '?')[0].toUpperCase()}
                              </div>
                              <h3 className="font-semibold text-sm truncate">{app.candidate_name || 'Unknown'}</h3>
                              <Badge variant={config.variant} className="shrink-0">{config.label}</Badge>
                              {app.match_score != null && app.match_score >= 80 && (
                                <Badge variant="outline" className="text-[10px] gap-0.5 text-green-600 border-green-200 bg-green-50 shrink-0">
                                  <Zap className="h-2.5 w-2.5" /> Top Match
                                </Badge>
                              )}
                            </div>
                            <div className="flex flex-wrap items-center gap-3 text-xs text-muted-foreground">
                              <span className="flex items-center gap-1">
                                <Mail className="h-3 w-3" /> {app.candidate_email}
                              </span>
                              <span className="flex items-center gap-1">
                                <Clock className="h-3 w-3" /> {timeAgo(app.applied_at)}
                              </span>
                              {app.cover_letter && <span className="flex items-center gap-1"><FileText className="h-3 w-3" /> Cover letter</span>}
                            </div>
                          </div>
                        </div>
                        <div className="flex items-center gap-3 shrink-0">
                          {app.match_score != null && (
                            <div className={`text-center rounded-lg border px-2 py-1 ${matchScoreBg(app.match_score)}`}>
                              <div className="text-base font-bold">{app.match_score}%</div>
                              <div className="text-[9px] uppercase font-medium">Match</div>
                            </div>
                          )}
                          <Select
                            value={app.status}
                            onChange={e => { e.stopPropagation(); updateStatus(app.id, e.target.value) }}
                            onClick={e => e.stopPropagation()}
                            className="w-32 text-xs"
                          >
                            {statuses.map(s => (
                              <option key={s} value={s}>{statusConfig[s]?.label || s}</option>
                            ))}
                          </Select>
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                )
              })}
            </div>
          )}
        </>
      )}

      {/* Detail dialog */}
      {selected && (
        <Dialog open={true} onClose={() => setSelected(null)} className="max-w-2xl">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-full bg-primary/10 text-primary font-semibold">
                {(selected.candidate_name || '?')[0].toUpperCase()}
              </div>
              <div>
                <div>{selected.candidate_name}</div>
                <p className="text-sm text-muted-foreground font-normal">{selected.candidate_email}</p>
              </div>
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            {/* Stats grid */}
            <div className="grid grid-cols-2 gap-3">
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Applied</p>
                <p className="font-medium text-sm">{new Date(selected.applied_at).toLocaleDateString()}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Status</p>
                <Badge variant={statusConfig[selected.status]?.variant || 'secondary'} className="mt-0.5">
                  {statusConfig[selected.status]?.label || selected.status}
                </Badge>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Match Score</p>
                <p className={`font-bold text-lg ${selected.match_score != null ? matchScoreColor(selected.match_score) : ''}`}>
                  {selected.match_score != null ? `${selected.match_score}%` : 'N/A'}
                </p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">OmniScore</p>
                <p className="font-medium text-sm">{selected.current_omniscore || selected.omniscore_at_apply || 'N/A'}</p>
              </div>
            </div>

            {/* Skills breakdown */}
            <SkillsBreakdown
              matchingSkills={parseSkills(selected.matching_skills)}
              missingSkills={parseSkills(selected.missing_skills)}
            />

            {/* Cover letter */}
            {selected.cover_letter && (
              <div>
                <h4 className="font-medium text-sm mb-1 flex items-center gap-1">
                  <FileText className="h-4 w-4" /> Cover Letter
                </h4>
                <div className="rounded-lg bg-muted/50 p-3 text-sm whitespace-pre-wrap leading-relaxed max-h-40 overflow-y-auto">
                  {selected.cover_letter}
                </div>
              </div>
            )}

            {/* Screening answers */}
            {(() => {
              if (!selected.screening_answers) return null
              try {
                const answers = typeof selected.screening_answers === 'string' ? JSON.parse(selected.screening_answers) : selected.screening_answers
                if (!answers || Object.keys(answers).length === 0) return null
                return (
                  <div>
                    <h4 className="font-medium text-sm mb-2 flex items-center gap-1">
                      <MessageSquare className="h-4 w-4" /> Screening Answers
                    </h4>
                    <div className="space-y-2">
                      {Object.entries(answers).map(([key, value], i) => (
                        <div key={key} className="rounded-lg bg-muted/50 p-3">
                          <p className="text-xs text-muted-foreground mb-1 font-medium">{getQuestionLabel(key, i)}</p>
                          <p className="text-sm">{String(value)}</p>
                        </div>
                      ))}
                    </div>
                  </div>
                )
              } catch { return null }
            })()}

            {/* AI Candidate Summary */}
            <div>
              <div className="flex items-center justify-between mb-2">
                <h4 className="font-medium text-sm flex items-center gap-1">
                  <Sparkles className="h-4 w-4 text-primary" /> AI Assessment
                </h4>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => generateAiSummary(selected.id)}
                  disabled={aiSummaryLoading}
                  className="h-7 text-xs gap-1 border-primary/30 text-primary hover:bg-primary hover:text-white"
                >
                  {aiSummaryLoading ? <Loader2 className="h-3 w-3 animate-spin" /> : <Sparkles className="h-3 w-3" />}
                  {aiSummaryLoading ? 'Analyzing...' : aiSummary ? 'Refresh' : 'Generate Summary'}
                </Button>
              </div>
              {aiSummaryLoading && (
                <div className="flex items-center gap-2 text-sm text-primary py-4 justify-center">
                  <Loader2 className="h-4 w-4 animate-spin" />
                  AI is analyzing this candidate's profile, skills, and application...
                </div>
              )}
              {aiSummary && !aiSummaryLoading && (
                <div className="rounded-lg bg-blue-50/50 border border-blue-100 p-3 space-y-2 text-sm">
                  {aiSummary.split('\n\n').map((paragraph, i) => {
                    const boldMatch = paragraph.match(/^\*\*(.+?):\*\*\s*(.+)$/)
                    if (boldMatch) {
                      return (
                        <div key={i}>
                          <span className="font-semibold text-blue-900">{boldMatch[1]}:</span>{' '}
                          <span className="text-blue-800">{boldMatch[2]}</span>
                        </div>
                      )
                    }
                    return <p key={i} className="text-blue-800">{paragraph}</p>
                  })}
                </div>
              )}
            </div>

            {/* Recruiter notes */}
            <div>
              <h4 className="font-medium text-sm mb-1">Recruiter Notes</h4>
              <Textarea
                value={notes}
                onChange={e => setNotes(e.target.value)}
                placeholder="Add notes about this candidate..."
                rows={3}
              />
            </div>

            {/* Status controls */}
            <div className="flex items-center gap-3 pt-2 border-t">
              <span className="text-sm font-medium">Status:</span>
              <Select
                value={selected.status}
                onChange={e => updateStatus(selected.id, e.target.value)}
                className="w-40"
                disabled={updating}
              >
                {statuses.map(s => (
                  <option key={s} value={s}>{statusConfig[s]?.label || s}</option>
                ))}
              </Select>
              <Button
                size="sm"
                onClick={() => {
                  updateStatus(selected.id, selected.status)
                  setSelected(null)
                }}
                disabled={updating}
              >
                Save & Close
              </Button>
            </div>

            {/* Make Offer button */}
            {!['rejected', 'offered', 'hired', 'withdrawn'].includes(selected.status) && (
              <Button
                className="w-full gap-2"
                onClick={() => navigate(`/recruiter/offers?create=1&candidateId=${selected.candidate_id}&jobId=${id}`)}
              >
                <Gift className="h-4 w-4" /> Make Offer to {selected.candidate_name?.split(' ')[0] || 'Candidate'}
              </Button>
            )}
          </div>
        </Dialog>
      )}
    </div>
  )
}

// Skills breakdown component (SmartRecruiters-style)
function SkillsBreakdown({ matchingSkills, missingSkills }: { matchingSkills: string[]; missingSkills: string[] }) {
  if (matchingSkills.length === 0 && missingSkills.length === 0) return null

  const total = matchingSkills.length + missingSkills.length
  const pct = total > 0 ? Math.round((matchingSkills.length / total) * 100) : 0

  return (
    <div>
      <h4 className="font-medium text-sm mb-2 flex items-center gap-1.5">
        <Target className="h-4 w-4 text-primary" />
        Skills Analysis
        <span className={`text-xs font-bold ${matchScoreColor(pct)}`}>({pct}% match)</span>
      </h4>
      {/* Progress bar */}
      <div className="h-2 rounded-full bg-muted overflow-hidden mb-3">
        <div
          className={`h-full rounded-full transition-all ${pct >= 80 ? 'bg-green-500' : pct >= 60 ? 'bg-amber-500' : 'bg-red-500'}`}
          style={{ width: `${pct}%` }}
        />
      </div>
      <div className="grid grid-cols-2 gap-3">
        {matchingSkills.length > 0 && (
          <div className="rounded-lg bg-green-50 border border-green-100 p-2.5">
            <p className="text-[10px] font-semibold text-green-700 mb-1.5 uppercase">Matching ({matchingSkills.length})</p>
            <div className="flex flex-wrap gap-1">
              {matchingSkills.slice(0, 8).map(s => (
                <span key={s} className="text-[10px] bg-green-100 text-green-700 rounded px-1.5 py-0.5">{s}</span>
              ))}
              {matchingSkills.length > 8 && (
                <span className="text-[10px] text-green-600">+{matchingSkills.length - 8} more</span>
              )}
            </div>
          </div>
        )}
        {missingSkills.length > 0 && (
          <div className="rounded-lg bg-amber-50 border border-amber-100 p-2.5">
            <p className="text-[10px] font-semibold text-amber-700 mb-1.5 uppercase">Gaps ({missingSkills.length})</p>
            <div className="flex flex-wrap gap-1">
              {missingSkills.slice(0, 8).map(s => (
                <span key={s} className="text-[10px] bg-amber-100 text-amber-700 rounded px-1.5 py-0.5">{s}</span>
              ))}
              {missingSkills.length > 8 && (
                <span className="text-[10px] text-amber-600">+{missingSkills.length - 8} more</span>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  )
}

import { useEffect, useState, useRef } from 'react'
import { useSearchParams } from 'react-router-dom'
import { apiCall } from '@/lib/api'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { Select } from '@/components/ui/select'
import { Dialog, DialogHeader, DialogTitle } from '@/components/ui/dialog'
import {
  Gift, Plus, Send, DollarSign, Calendar, CheckCircle, XCircle, Clock, Eye,
  Ban, FileText, User, Briefcase, Building2, Sparkles, Download, RefreshCw,
  MapPin, UserCheck, PenTool,
} from 'lucide-react'

interface Offer {
  id: number
  candidate_id: number
  job_id: number
  title: string
  company_name: string
  candidate_name: string
  candidate_email: string
  job_title: string
  recruiter_name: string
  salary: number
  start_date: string
  benefits: string
  reporting_to: string
  location: string
  employment_type: string
  status: string
  sent_at: string
  viewed_at: string
  accepted_at: string
  declined_at: string
  decline_reason: string
  created_at: string
  has_letter: boolean
  offer_letter_html: string
  offer_letter_generated_at: string
  candidate_signature: string
  candidate_signed_at: string
}

interface Candidate {
  id: number
  name: string
  email: string
}

interface Job {
  id: number
  title: string
  location?: string
}

const statusConfig: Record<string, { label: string; variant: 'default' | 'secondary' | 'success' | 'warning' | 'destructive'; icon: React.ElementType }> = {
  draft: { label: 'Draft', variant: 'secondary', icon: Clock },
  sent: { label: 'Sent', variant: 'warning', icon: Send },
  viewed: { label: 'Viewed', variant: 'default', icon: Eye },
  accepted: { label: 'Accepted', variant: 'success', icon: CheckCircle },
  declined: { label: 'Declined', variant: 'destructive', icon: XCircle },
  withdrawn: { label: 'Withdrawn', variant: 'secondary', icon: Ban },
}

export function RecruiterOffersPage() {
  const [searchParams, setSearchParams] = useSearchParams()
  const [offers, setOffers] = useState<Offer[]>([])
  const [candidates, setCandidates] = useState<Candidate[]>([])
  const [jobs, setJobs] = useState<Job[]>([])
  const [loading, setLoading] = useState(true)
  const [showCreate, setShowCreate] = useState(false)
  const [saving, setSaving] = useState(false)
  const [sending, setSending] = useState<number | null>(null)
  const [selectedOffer, setSelectedOffer] = useState<Offer | null>(null)
  const [withdrawing, setWithdrawing] = useState(false)
  const [statusFilter, setStatusFilter] = useState('')
  const [generating, setGenerating] = useState(false)
  const [previewHtml, setPreviewHtml] = useState('')
  const [showPreview, setShowPreview] = useState(false)
  const [previewOfferId, setPreviewOfferId] = useState<number | null>(null)

  // Form fields
  const [candidateId, setCandidateId] = useState('')
  const [jobId, setJobId] = useState('')
  const [offerTitle, setOfferTitle] = useState('')
  const [salary, setSalary] = useState('')
  const [startDate, setStartDate] = useState('')
  const [benefits, setBenefits] = useState('')
  const [reportingTo, setReportingTo] = useState('')
  const [location, setLocation] = useState('')
  const [employmentType, setEmploymentType] = useState('full-time')

  useEffect(() => {
    loadData()
  }, [])

  // Handle query params for pre-filled offer creation
  useEffect(() => {
    const create = searchParams.get('create')
    const cId = searchParams.get('candidateId')
    const jId = searchParams.get('jobId')

    if (create === '1') {
      if (cId) setCandidateId(cId)
      if (jId) setJobId(jId)
      setShowCreate(true)
      setSearchParams({}, { replace: true })
    }
  }, [searchParams])

  async function loadData() {
    try {
      const [offersRes, candidatesRes, jobsRes] = await Promise.allSettled([
        apiCall<Offer[]>('/onboarding/offers'),
        apiCall<{ candidates: Candidate[] }>('/recruiter/candidates'),
        apiCall<{ jobs: Job[] }>('/recruiter/jobs'),
      ])
      if (offersRes.status === 'fulfilled') setOffers(Array.isArray(offersRes.value) ? offersRes.value : [])
      if (candidatesRes.status === 'fulfilled') setCandidates(candidatesRes.value.candidates || [])
      if (jobsRes.status === 'fulfilled') setJobs(jobsRes.value.jobs || [])
    } catch {
      // silent
    } finally {
      setLoading(false)
    }
  }

  async function createOffer() {
    if (!candidateId || !jobId || !salary) {
      alert('Please fill in candidate, job, and salary')
      return
    }
    setSaving(true)
    try {
      const newOffer = await apiCall<Offer>('/onboarding/offers', {
        method: 'POST',
        body: {
          candidate_id: Number(candidateId),
          job_id: Number(jobId),
          title: offerTitle || jobs.find(j => j.id === Number(jobId))?.title || 'Job Offer',
          salary: Number(salary),
          start_date: startDate || null,
          benefits,
          reporting_to: reportingTo || null,
          location: location || null,
          employment_type: employmentType,
        },
      })
      setShowCreate(false)
      resetForm()
      await loadData()
      // Auto-open the new offer to generate a letter
      if (newOffer?.id) {
        const refreshed = offers.find(o => o.id === newOffer.id) || newOffer
        setSelectedOffer(refreshed as Offer)
      }
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Failed to create offer')
    } finally {
      setSaving(false)
    }
  }

  async function generateLetter(offerId: number) {
    setGenerating(true)
    try {
      const result = await apiCall<{ success: boolean; offer_letter_html: string }>(`/onboarding/offers/${offerId}/generate-letter`, {
        method: 'POST',
      })
      if (result.offer_letter_html) {
        setPreviewHtml(result.offer_letter_html)
        setPreviewOfferId(offerId)
        setShowPreview(true)
        // Update the offer in local state
        setOffers(prev => prev.map(o => o.id === offerId ? { ...o, has_letter: true, offer_letter_html: result.offer_letter_html } : o))
        if (selectedOffer?.id === offerId) {
          setSelectedOffer(prev => prev ? { ...prev, has_letter: true, offer_letter_html: result.offer_letter_html } : null)
        }
      }
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Failed to generate offer letter')
    } finally {
      setGenerating(false)
    }
  }

  async function viewLetter(offerId: number) {
    try {
      const result = await apiCall<{ offer_letter_html: string }>(`/onboarding/offers/${offerId}/letter`)
      if (result.offer_letter_html) {
        setPreviewHtml(result.offer_letter_html)
        setPreviewOfferId(offerId)
        setShowPreview(true)
      }
    } catch {
      alert('Failed to load offer letter')
    }
  }

  async function sendOffer(id: number, e?: React.MouseEvent) {
    e?.stopPropagation()
    setSending(id)
    try {
      await apiCall(`/onboarding/offers/${id}/send`, { method: 'POST' })
      loadData()
      if (selectedOffer?.id === id) {
        setSelectedOffer(prev => prev ? { ...prev, status: 'sent', sent_at: new Date().toISOString() } : null)
      }
    } catch {
      // silent
    } finally {
      setSending(null)
    }
  }

  async function withdrawOffer(id: number) {
    if (!confirm('Are you sure you want to withdraw this offer?')) return
    setWithdrawing(true)
    try {
      await apiCall(`/onboarding/offers/${id}/withdraw`, { method: 'POST' })
      setSelectedOffer(null)
      loadData()
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Failed to withdraw offer')
    } finally {
      setWithdrawing(false)
    }
  }

  function resetForm() {
    setCandidateId('')
    setJobId('')
    setOfferTitle('')
    setSalary('')
    setStartDate('')
    setBenefits('')
    setReportingTo('')
    setLocation('')
    setEmploymentType('full-time')
  }

  const allStatuses = ['draft', 'sent', 'viewed', 'accepted', 'declined', 'withdrawn']
  const statusCounts = allStatuses.reduce((acc, s) => {
    acc[s] = offers.filter(o => o.status === s).length
    return acc
  }, {} as Record<string, number>)

  const filtered = offers.filter(o => !statusFilter || o.status === statusFilter)

  const draftOffers = filtered.filter(o => o.status === 'draft')
  const pendingOffers = filtered.filter(o => ['sent', 'viewed'].includes(o.status))
  const resolvedOffers = filtered.filter(o => ['accepted', 'declined', 'withdrawn'].includes(o.status))

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="font-heading text-2xl font-bold">Offers</h1>
          <p className="text-muted-foreground">Create AI-generated professional offer letters</p>
        </div>
        <Button onClick={() => setShowCreate(true)} className="gap-2">
          <Plus className="h-4 w-4" /> Create Offer
        </Button>
      </div>

      {/* Stats */}
      <div className="grid gap-3 sm:grid-cols-4">
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold">{offers.length}</p>
            <p className="text-xs text-muted-foreground">Total</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-amber-600">
              {offers.filter(o => ['sent', 'viewed'].includes(o.status)).length}
            </p>
            <p className="text-xs text-muted-foreground">Pending</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-emerald-600">
              {offers.filter(o => o.status === 'accepted').length}
            </p>
            <p className="text-xs text-muted-foreground">Accepted</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-destructive">
              {offers.filter(o => o.status === 'declined').length}
            </p>
            <p className="text-xs text-muted-foreground">Declined</p>
          </CardContent>
        </Card>
      </div>

      {/* Status filter pills */}
      <div className="flex flex-wrap gap-2">
        <Button
          variant={!statusFilter ? 'default' : 'outline'}
          size="sm"
          onClick={() => setStatusFilter('')}
        >
          All ({offers.length})
        </Button>
        {allStatuses.map(s => (
          statusCounts[s] > 0 ? (
            <Button
              key={s}
              variant={statusFilter === s ? 'default' : 'outline'}
              size="sm"
              onClick={() => setStatusFilter(s)}
            >
              {statusConfig[s]?.label || s} ({statusCounts[s]})
            </Button>
          ) : null
        ))}
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-16">
          <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
        </div>
      ) : filtered.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <Gift className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground mb-4">
              {offers.length === 0 ? 'No offers created yet' : 'No offers match this filter'}
            </p>
            {offers.length === 0 && (
              <Button onClick={() => setShowCreate(true)} className="gap-2">
                <Plus className="h-4 w-4" /> Create Your First Offer
              </Button>
            )}
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-6">
          {/* Draft offers */}
          {draftOffers.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">
                Drafts ({draftOffers.length})
              </h2>
              <div className="space-y-2">
                {draftOffers.map(offer => (
                  <OfferRow
                    key={offer.id}
                    offer={offer}
                    onSend={(e) => sendOffer(offer.id, e)}
                    sending={sending === offer.id}
                    onClick={() => setSelectedOffer(offer)}
                  />
                ))}
              </div>
            </div>
          )}

          {/* Pending */}
          {pendingOffers.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">
                Pending Response ({pendingOffers.length})
              </h2>
              <div className="space-y-2">
                {pendingOffers.map(offer => (
                  <OfferRow key={offer.id} offer={offer} onClick={() => setSelectedOffer(offer)} />
                ))}
              </div>
            </div>
          )}

          {/* Resolved */}
          {resolvedOffers.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">
                Resolved ({resolvedOffers.length})
              </h2>
              <div className="space-y-2">
                {resolvedOffers.map(offer => (
                  <OfferRow key={offer.id} offer={offer} onClick={() => setSelectedOffer(offer)} />
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {/* Offer detail dialog */}
      {selectedOffer && !showPreview && (
        <Dialog open={true} onClose={() => setSelectedOffer(null)} className="max-w-lg">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Gift className="h-5 w-5 text-primary" />
              Offer Details
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            {/* Status badge */}
            {(() => {
              const config = statusConfig[selectedOffer.status] || { label: selectedOffer.status, variant: 'secondary' as const, icon: Clock }
              const Icon = config.icon
              return (
                <Badge variant={config.variant} className="gap-1 w-fit">
                  <Icon className="h-3 w-3" /> {config.label}
                </Badge>
              )
            })()}

            {/* Details grid */}
            <div className="grid grid-cols-2 gap-3">
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <User className="h-3 w-3" /> Candidate
                </p>
                <p className="font-medium">{selectedOffer.candidate_name || 'Unknown'}</p>
                <p className="text-xs text-muted-foreground">{selectedOffer.candidate_email}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <Briefcase className="h-3 w-3" /> Position
                </p>
                <p className="font-medium">{selectedOffer.job_title || selectedOffer.title}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <DollarSign className="h-3 w-3" /> Salary
                </p>
                <p className="font-medium text-emerald-600">
                  ${Number(selectedOffer.salary).toLocaleString()}/yr
                </p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <Calendar className="h-3 w-3" /> Start Date
                </p>
                <p className="font-medium">
                  {selectedOffer.start_date
                    ? new Date(selectedOffer.start_date).toLocaleDateString()
                    : 'TBD'}
                </p>
              </div>
            </div>

            {/* Offer Letter Status */}
            <div className="rounded-lg border p-4">
              <div className="flex items-center justify-between mb-2">
                <div className="flex items-center gap-2">
                  <FileText className="h-4 w-4 text-primary" />
                  <span className="font-medium text-sm">Offer Letter Document</span>
                </div>
                {selectedOffer.has_letter && (
                  <Badge variant="success" className="gap-1 text-xs">
                    <CheckCircle className="h-3 w-3" /> Generated
                  </Badge>
                )}
              </div>
              {selectedOffer.has_letter ? (
                <div className="flex gap-2">
                  <Button
                    size="sm"
                    variant="outline"
                    className="gap-1"
                    onClick={() => viewLetter(selectedOffer.id)}
                  >
                    <Eye className="h-3 w-3" /> Preview
                  </Button>
                  <Button
                    size="sm"
                    variant="outline"
                    className="gap-1"
                    onClick={() => generateLetter(selectedOffer.id)}
                    disabled={generating}
                  >
                    {generating ? (
                      <div className="h-3 w-3 animate-spin rounded-full border-2 border-current border-t-transparent" />
                    ) : (
                      <RefreshCw className="h-3 w-3" />
                    )}
                    Regenerate
                  </Button>
                </div>
              ) : (
                <Button
                  size="sm"
                  className="gap-2"
                  onClick={() => generateLetter(selectedOffer.id)}
                  disabled={generating}
                >
                  {generating ? (
                    <>
                      <div className="h-4 w-4 animate-spin rounded-full border-2 border-white border-t-transparent" />
                      AI is writing your offer letter...
                    </>
                  ) : (
                    <>
                      <Sparkles className="h-4 w-4" />
                      Generate Offer Letter with AI
                    </>
                  )}
                </Button>
              )}
            </div>

            {/* Signature status */}
            {selectedOffer.candidate_signed_at && (
              <div className="rounded-lg bg-emerald-50 border border-emerald-200 p-3">
                <div className="flex items-center gap-2 mb-1">
                  <PenTool className="h-4 w-4 text-emerald-600" />
                  <span className="font-medium text-sm text-emerald-800">E-Signed by Candidate</span>
                </div>
                <p className="text-xs text-emerald-700">
                  Signed on {new Date(selectedOffer.candidate_signed_at).toLocaleString()}
                </p>
              </div>
            )}

            {/* Benefits */}
            {selectedOffer.benefits && (
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground mb-1">Benefits</p>
                <p className="text-sm whitespace-pre-wrap">{selectedOffer.benefits}</p>
              </div>
            )}

            {/* Timeline */}
            <div className="rounded-lg border p-3 space-y-2">
              <p className="text-xs font-medium text-muted-foreground uppercase tracking-wider">Timeline</p>
              <div className="space-y-1 text-sm">
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Created</span>
                  <span>{new Date(selectedOffer.created_at).toLocaleDateString()}</span>
                </div>
                {selectedOffer.sent_at && (
                  <div className="flex justify-between">
                    <span className="text-muted-foreground">Sent</span>
                    <span>{new Date(selectedOffer.sent_at).toLocaleDateString()}</span>
                  </div>
                )}
                {selectedOffer.viewed_at && (
                  <div className="flex justify-between">
                    <span className="text-muted-foreground">Viewed</span>
                    <span>{new Date(selectedOffer.viewed_at).toLocaleDateString()}</span>
                  </div>
                )}
                {selectedOffer.accepted_at && (
                  <div className="flex justify-between text-emerald-600">
                    <span>Accepted</span>
                    <span>{new Date(selectedOffer.accepted_at).toLocaleDateString()}</span>
                  </div>
                )}
                {selectedOffer.declined_at && (
                  <div className="flex justify-between text-destructive">
                    <span>Declined</span>
                    <span>{new Date(selectedOffer.declined_at).toLocaleDateString()}</span>
                  </div>
                )}
              </div>
            </div>

            {/* Decline reason */}
            {selectedOffer.decline_reason && (
              <div className="rounded-lg bg-destructive/10 p-3">
                <p className="text-xs text-muted-foreground mb-1">Decline Reason</p>
                <p className="text-sm">{selectedOffer.decline_reason}</p>
              </div>
            )}

            {/* Actions */}
            <div className="flex gap-2 pt-2">
              {selectedOffer.status === 'draft' && (
                <>
                  <Button
                    onClick={() => sendOffer(selectedOffer.id)}
                    disabled={sending === selectedOffer.id || !selectedOffer.has_letter}
                    className="gap-2 flex-1"
                    title={!selectedOffer.has_letter ? 'Generate offer letter first' : ''}
                  >
                    {sending === selectedOffer.id ? (
                      <div className="h-4 w-4 animate-spin rounded-full border-2 border-white border-t-transparent" />
                    ) : (
                      <Send className="h-4 w-4" />
                    )}
                    {selectedOffer.has_letter ? 'Send to Candidate' : 'Generate Letter First'}
                  </Button>
                  <Button
                    variant="outline"
                    onClick={() => withdrawOffer(selectedOffer.id)}
                    disabled={withdrawing}
                    className="gap-2"
                  >
                    <Ban className="h-4 w-4" /> Delete
                  </Button>
                </>
              )}
              {['sent', 'viewed'].includes(selectedOffer.status) && (
                <Button
                  variant="outline"
                  onClick={() => withdrawOffer(selectedOffer.id)}
                  disabled={withdrawing}
                  className="gap-2 text-destructive"
                >
                  {withdrawing ? (
                    <div className="h-4 w-4 animate-spin rounded-full border-2 border-current border-t-transparent" />
                  ) : (
                    <Ban className="h-4 w-4" />
                  )}
                  Withdraw Offer
                </Button>
              )}
            </div>
          </div>
        </Dialog>
      )}

      {/* Offer Letter Preview Dialog */}
      {showPreview && (
        <Dialog
          open={true}
          onClose={() => { setShowPreview(false); setPreviewHtml(''); setPreviewOfferId(null) }}
          className="max-w-4xl"
        >
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <FileText className="h-5 w-5 text-primary" />
              Offer Letter Preview
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            {/* Letter preview in a document-style container */}
            <div className="bg-white rounded-lg border shadow-inner overflow-auto max-h-[70vh]">
              <div
                className="p-8"
                dangerouslySetInnerHTML={{ __html: previewHtml }}
              />
            </div>
            <div className="flex gap-2 justify-end">
              <Button
                variant="outline"
                className="gap-2"
                onClick={() => {
                  if (previewOfferId) generateLetter(previewOfferId)
                }}
                disabled={generating}
              >
                {generating ? (
                  <div className="h-4 w-4 animate-spin rounded-full border-2 border-current border-t-transparent" />
                ) : (
                  <RefreshCw className="h-4 w-4" />
                )}
                Regenerate
              </Button>
              <Button
                className="gap-2"
                onClick={() => {
                  setShowPreview(false)
                  setPreviewHtml('')
                  setPreviewOfferId(null)
                }}
              >
                <CheckCircle className="h-4 w-4" />
                Looks Good
              </Button>
            </div>
          </div>
        </Dialog>
      )}

      {/* Create offer dialog */}
      <Dialog open={showCreate} onClose={() => { setShowCreate(false); resetForm() }} className="max-w-lg">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Sparkles className="h-5 w-5 text-primary" />
            Create Offer Letter
          </DialogTitle>
        </DialogHeader>
        <p className="text-sm text-muted-foreground -mt-2 mb-2">
          Fill in the key terms below. AI will generate a professional offer letter document.
        </p>
        <div className="space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <Label>Candidate *</Label>
              <Select value={candidateId} onChange={e => setCandidateId(e.target.value)} className="mt-1">
                <option value="">Select candidate...</option>
                {candidates.map(c => (
                  <option key={c.id} value={c.id}>{c.name} ({c.email})</option>
                ))}
              </Select>
            </div>
            <div>
              <Label>Job Position *</Label>
              <Select value={jobId} onChange={e => setJobId(e.target.value)} className="mt-1">
                <option value="">Select job...</option>
                {jobs.map(j => (
                  <option key={j.id} value={j.id}>{j.title}</option>
                ))}
              </Select>
            </div>
          </div>
          <div>
            <Label>Offer Title</Label>
            <Input
              value={offerTitle}
              onChange={e => setOfferTitle(e.target.value)}
              placeholder="e.g. Senior Engineer Offer"
              className="mt-1"
            />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <Label>Annual Salary ($) *</Label>
              <Input
                type="number"
                value={salary}
                onChange={e => setSalary(e.target.value)}
                placeholder="e.g. 120000"
                className="mt-1"
              />
            </div>
            <div>
              <Label>Start Date</Label>
              <Input
                type="date"
                value={startDate}
                onChange={e => setStartDate(e.target.value)}
                className="mt-1"
              />
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <Label>Reporting To</Label>
              <Input
                value={reportingTo}
                onChange={e => setReportingTo(e.target.value)}
                placeholder="e.g. VP of Engineering"
                className="mt-1"
              />
            </div>
            <div>
              <Label>Location</Label>
              <Input
                value={location}
                onChange={e => setLocation(e.target.value)}
                placeholder="e.g. San Francisco, CA"
                className="mt-1"
              />
            </div>
          </div>
          <div>
            <Label>Employment Type</Label>
            <Select value={employmentType} onChange={e => setEmploymentType(e.target.value)} className="mt-1">
              <option value="full-time">Full-time</option>
              <option value="part-time">Part-time</option>
              <option value="contract">Contract</option>
              <option value="internship">Internship</option>
            </Select>
          </div>
          <div>
            <Label>Benefits</Label>
            <Textarea
              value={benefits}
              onChange={e => setBenefits(e.target.value)}
              placeholder="Health insurance, 401k, PTO, stock options, etc..."
              rows={3}
              className="mt-1"
            />
          </div>
          <div className="flex gap-2 pt-2">
            <Button onClick={createOffer} disabled={saving} className="gap-2">
              {saving ? (
                <div className="h-4 w-4 animate-spin rounded-full border-2 border-white border-t-transparent" />
              ) : (
                <Gift className="h-4 w-4" />
              )}
              Create Offer
            </Button>
            <Button variant="outline" onClick={() => { setShowCreate(false); resetForm() }}>Cancel</Button>
          </div>
        </div>
      </Dialog>
    </div>
  )
}

function OfferRow({ offer, onSend, sending, onClick }: {
  offer: Offer
  onSend?: (e: React.MouseEvent) => void
  sending?: boolean
  onClick?: () => void
}) {
  const config = statusConfig[offer.status] || { label: offer.status, variant: 'secondary' as const, icon: Clock }
  const Icon = config.icon

  return (
    <Card className="cursor-pointer transition-shadow hover:shadow-md" onClick={onClick}>
      <CardContent className="p-4">
        <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
          <div className="min-w-0">
            <div className="flex items-center gap-2 mb-1">
              <h3 className="font-semibold truncate">{offer.candidate_name || 'Unknown'}</h3>
              <Badge variant={config.variant} className="gap-1">
                <Icon className="h-3 w-3" /> {config.label}
              </Badge>
              {offer.has_letter && (
                <Badge variant="default" className="gap-1 text-xs bg-indigo-100 text-indigo-700 border-indigo-200">
                  <FileText className="h-3 w-3" /> Letter
                </Badge>
              )}
            </div>
            <div className="flex flex-wrap items-center gap-3 text-xs text-muted-foreground">
              <span className="flex items-center gap-1">
                <Briefcase className="h-3 w-3" />
                {offer.job_title || offer.title}
              </span>
              <span className="flex items-center gap-1">
                <DollarSign className="h-3 w-3" />
                ${Number(offer.salary).toLocaleString()}/yr
              </span>
              {offer.start_date && (
                <span className="flex items-center gap-1">
                  <Calendar className="h-3 w-3" />
                  Start: {new Date(offer.start_date).toLocaleDateString()}
                </span>
              )}
              {offer.decline_reason && (
                <span className="text-destructive">Reason: {offer.decline_reason}</span>
              )}
            </div>
          </div>
          <div className="flex items-center gap-2 shrink-0">
            {offer.status === 'draft' && onSend && (
              <Button size="sm" onClick={onSend} disabled={sending || !offer.has_letter} className="gap-1">
                {sending ? (
                  <div className="h-3 w-3 animate-spin rounded-full border-2 border-white border-t-transparent" />
                ) : (
                  <Send className="h-3 w-3" />
                )}
                Send
              </Button>
            )}
          </div>
        </div>
      </CardContent>
    </Card>
  )
}

